@keyframes fadeData { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } } .tab-content::-webkit-scrollbar { width: 4px; } .tab-content::-webkit-scrollbar-thumb { background: rgba(255, 126, 179, 0.7); border-radius: 4px; }

