.eff-normal .data-val { color: #cbd5e1; } .eff-normal { border-left-color: rgba(100, 130, 170, 0.4); }
    .eff-wet .data-val { color: #b8d8ff; text-shadow: 0 0 6px rgba(100, 160, 255, 0.5); font-style: italic; } .eff-wet { border-left-color: #5090d0; background: linear-gradient(90deg, rgba(92, 225, 230, 0.1), rgba(0,0,0,0.4)); animation: p-wet 3s infinite alternate; } @keyframes p-wet { 0% { box-shadow: inset 3px 0 8px rgba(92,225,230,0); } 100% { box-shadow: inset 3px 0 12px rgba(92,225,230,0.4); } }
    .eff-sticky .data-val { color: #fffdee; text-shadow: 0 1px 3px rgba(0,0,0,0.9), 0 0 8px rgba(255,255,255,0.6); font-weight: 900;} .eff-sticky { border-left-color: #ffffff; border-left-width: 3px; background: linear-gradient(135deg, rgba(255, 255, 255, 0.15) 0%, rgba(0,0,0,0.4) 70%); } .eff-sticky::before { content: ''; position: absolute; left: -5px; bottom: 8px; width: 7px; height: 7px; background: #ffffff; border-radius: 50%; box-shadow: 0 0 5px #fff; animation: semen-drop 2.5s ease-in infinite; opacity: 0; z-index: 2; } .eff-sticky::after { content: ''; position: absolute; left: -2.5px; top: auto; bottom: 10px; width: 2px; background: linear-gradient(180deg, rgba(255,255,255,0) 0%, rgba(255,255,255,0.9) 100%); animation: semen-string 2.5s ease-in infinite; opacity: 0; transform-origin: top; z-index: 1; } @keyframes semen-drop { 0% { transform: translateY(-10px) scale(0.5); opacity: 0;} 20% { opacity: 0.9; transform: translateY(-5px) scale(1);} 80% { transform: translateY(18px) scale(1.1); opacity: 0.8;} 85%, 100% { opacity: 0; transform: translateY(20px);} } @keyframes semen-string { 0% { height: 0px; opacity: 0; transform: translateY(-10px);} 20% { opacity: 0.8; height: 5px; transform: translateY(-5px);} 80% { height: 25px; opacity: 0.6; transform: translateY(-5px);} 85%, 100% { opacity: 0; height: 0;} }
