    .bar-row { display: flex; align-items: center; padding: 6px 0; border-bottom: 1px solid rgba(255,255,255,0.03); position: relative; } .bar-row:last-child { border-bottom: none; } .bar-key { font-weight: 900; font-size: 0.85em; margin-right: 12px; flex-shrink: 0; transition: color 0.4s;} .bar-wrap { flex: 1; background: rgba(0,0,0,0.7); border-radius: 8px; height: 8px; position: relative; margin-right: 12px; border: 1px solid rgba(255,255,255,0.15); overflow: hidden; box-shadow: inset 0 1px 4px rgba(0,0,0,0.9); } .bar-fill { height: 100%; border-radius: 8px; box-shadow: 0 0 4px rgba(255, 255, 255, 0.15); position: relative; transition: width 0.8s cubic-bezier(0.34, 1.56, 0.64, 1); min-width: 2%;} .bar-num { color: #fff; font-weight: 900; text-align: right; font-size: 0.85em; flex-shrink:0; min-width: 45px;} .desc-append { margin-top: 3px; padding: 3px 8px 3px 10px; background: rgba(0,0,0,0.25); border-radius: 0 0 4px 4px; border-left: 2px solid rgba(255,255,255,0.12); font-size: 0.75em; opacity: 0.85; color: rgba(255,255,255,0.75); line-height: 1.45; }
