.desc-append .data-val::before { content: '🪝 '; font-size: 0.9em; opacity: 0.6; } .bar-wrap.drip-enabled { overflow: visible !important; } .ov-drip-drop { position: absolute; right: -2px; top: 100%; width: 5px; height: 5px; background: #ff7eb3; border-radius: 50%; box-shadow: 0 0 6px #ff7eb3, inset 0 -1px 3px rgba(255,0,100,0.6); animation: pink-drip 1.2s ease-in infinite; z-index: 10; pointer-events: none; } .ov-drip-drop::before { content: ''; position: absolute; bottom: 80%; left: 50%; transform: translateX(-50%); width: 2px; height: 12px; background: linear-gradient(0deg, #ff7eb3, rgba(255,126,179,0)); animation: pink-drip-tail 1.2s ease-in infinite; } @keyframes pink-drip { 0% { transform: translateY(0) scale(0.2); opacity: 0; } 20% { transform: translateY(3px) scale(1.1); opacity: 0.9; } 70% { transform: translateY(18px) scale(0.9); opacity: 0.8; } 90% { transform: translateY(22px) scale(0.5); opacity: 0; } 100% { opacity: 0; } } @keyframes pink-drip-tail { 0% { height: 0px; opacity: 0; } 20% { height: 3px; opacity: 0.8; } 70% { height: 18px; opacity: 0.4; } 90%, 100% { height: 0; opacity: 0; } }
.tube-card { display: flex; flex-direction: column; padding: 6px 10px; background: rgba(0,0,0,0.4); border-radius: 6px; border-right: 2px solid rgba(255,255,255,0.1); border-left: 4px solid #fffdee; box-shadow: inset 0 0 10px rgba(0,0,0,0.8); position: relative; margin-bottom: 6px; transform: translateZ(0);} .tube-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 5px;} .tube-key { color: #fdfcee; font-weight: 900; font-size: 0.78em; letter-spacing: 0.5px; text-shadow: 0 0 2px rgba(255,255,255,0.18);} .tube-num { color: #fff; font-weight: 900; font-size: 0.82em; text-shadow: 0 0 3px rgba(255,255,255,0.3); letter-spacing: 1px;} .tube-container { width: 100%; height: 7px; background: rgba(10, 10, 15, 0.85); border-radius: 4px; border: 1px solid rgba(255,255,255,0.3); border-right-color: transparent; box-shadow: inset 0 2px 4px rgba(0,0,0,0.9), 0 1px 3px rgba(255,255,255,0.1); position: relative; overflow: visible; display: flex; align-items: center; padding: 1px; } .tube-container::before { content: ''; position: absolute; top: 1px; left: 2px; right: 2px; height: 2px; border-radius: 2px; background: linear-gradient(180deg, rgba(255,255,255,0.9) 0%, rgba(255,255,255,0.1) 100%); pointer-events: none; z-index: 3; } .tube-container::after { content: ''; position: absolute; bottom: 0; top: 0; left: 10px; right: 10px; background: repeating-linear-gradient(90deg, transparent, transparent 15%, rgba(255,255,255,0.2) 15%, rgba(255,255,255,0.2) 15.5%); pointer-events: none; z-index: 4; } .tube-fill { height: 100%; border-radius: 3px; background: linear-gradient(180deg, #ffffff 0%, #e0d8c8 100%); box-shadow: 0 0 12px rgba(255,253,238,0.7), inset -4px 0 5px rgba(0,0,0,0.3); transition: width 1s cubic-bezier(0.2, 0.8, 0.2, 1); position: relative; z-index: 2; }
.tube-fill.overload::after { content: ''; position: absolute; right: -8px; top: -6px; width: 5px; height: 5px; border-radius: 50%; background: #fff; pointer-events: none; filter: drop-shadow(0 0 4px #fff); box-shadow: -4px 8px 0 -1px #fffdee, -12px 4px 0 1px #fff, -20px 10px 0 0 #e0d8c8; animation: boil-bubble 0.8s ease-out infinite; z-index: 10; }
@keyframes boil-bubble { 0% { transform: translateY(0) scale(0.5); opacity: 0; } 30% { transform: translateY(-5px) scale(1.2); opacity: 0.9; } 100% { transform: translateY(-15px) scale(1.5); opacity: 0; box-shadow: -8px 15px 0 -1px rgba(255,253,238,0), -15px 8px 0 1px rgba(255,255,255,0), -25px 20px 0 0 rgba(224,216,200,0); } }
.tube-desc { margin-top: 5px; font-size: 0.75em; color: rgba(255,255,255,0.85); line-height: 1.4; font-weight: 600;}
    /* 防黑屏 GPU 加速催醒核心层 */
    .thrust-radar-container { margin-top: 10px; padding: 6px 10px; background: rgba(0, 0, 0, 0.6); border: 1px dashed rgba(255,255,255,0.2); border-radius: 6px; box-shadow: inset 0 0 5px rgba(0,0,0,0.8); display: flex; flex-direction: column; gap: 4px; position: relative; z-index: 3; transform: translateZ(0); will-change: transform; }
    .radar-label { font-family: monospace; font-size: 0.7em; font-weight: 900; color: rgba(255,255,255,0.7); text-shadow: 0 0 3px rgba(255,255,255,0.4); letter-spacing: 1px; display: flex; justify-content: space-between; }
    .thrust-radar-bar { width: 100%; height: 8px; background: #000; border-radius: 4px; position: relative; overflow: hidden; border: 1px solid rgba(255,255,255,0.1); box-shadow: inset 0 2px 4px rgba(0,0,0,0.9); transform: translateZ(0); }
