    .ed-input:focus { border-color: var(--kt-pink); box-shadow: 0 0 10px rgba(255,126,179,0.5), inset 0 0 10px rgba(255,126,179,0.3); }
    .ed-range-wrap { display: flex; flex-direction: column; width: 100%; gap: 10px; }
