    .ed-range::-webkit-slider-thumb { -webkit-appearance: none; height: 18px; width: 18px; background: var(--kt-pink); border-radius: 50%; margin-top: -6px; box-shadow: 0 0 8px var(--kt-pink); cursor: pointer; }
    .ed-btn-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 6px; }
