    .ed-confirm { background: linear-gradient(90deg, var(--kt-cyan), var(--kt-pink)); color: #fff; box-shadow: 0 2px 10px rgba(255,126,179,0.4); text-shadow: 0 1px 2px rgba(0,0,0,0.5); } .ed-confirm:active { transform: scale(0.95); }

