    /* 🌊 高潮过载·重力流瀑引擎 (Climax Overload & Gravity Slime) */
    /* ========================================================= */
    .climax-overload-active { animation: ui-convulsion 0.6s cubic-bezier(0.36, 0.07, 0.19, 0.97) both; }
    @keyframes ui-convulsion {
