        10% { transform: translateZ(0) scale(1.02) translate(-2px, 3px); filter: blur(2px) hue-rotate(-20deg); box-shadow: inset 0 0 15px rgba(255,255,255,0.35); }
        20% { transform: translateZ(0) scale(0.98) translate(3px, -2px); filter: blur(4px) hue-rotate(30deg); box-shadow: inset 0 0 25px rgba(255,30,106,0.45); }
        20% { transform: translateZ(0) scale(0.98) translate(3px, -2px); filter: blur(4px) hue-rotate(30deg); box-shadow: inset 0 0 50px rgba(255,30,106,0.9); }
        30% { transform: translateZ(0) scale(1.01) translate(-1px, 2px); filter: blur(1px) hue-rotate(-10deg); }
        40% { transform: translateZ(0) scale(0.99) translate(1px, -1px); filter: blur(3px) hue-rotate(20deg); }
        50% { transform: translateZ(0) scale(1) translate(0, 0); filter: blur(0px) hue-rotate(0deg); box-shadow: inset 0 0 15px rgba(255,255,255,0.5); }
        100% { transform: translateZ(0) scale(1); filter: blur(0px) hue-rotate(0deg); }
