    .stain-gravity-drip {
        background: radial-gradient(ellipse at 50% 80%, rgba(255, 255, 255, 0.95) 0%, rgba(255, 250, 240, 0.6) 40%, rgba(255, 255, 255, 0.1) 100%);
        backdrop-filter: blur(3px); -webkit-backdrop-filter: blur(3px);
        border-radius: 50% 50% 45% 45% / 80% 80% 30% 30%;
        box-shadow: inset 0 -4px 6px rgba(255,255,255,0.8), 0 5px 10px rgba(0,0,0,0.3);
        animation: splatter-in 0.3s ease-out forwards, drip-down var(--drip-spd) cubic-bezier(0.4, 0, 1, 1) forwards;
        animation-delay: 0s, 0.4s;
    }
    .stain-gravity-drip::before {
        content: ''; position: absolute; bottom: 90%; left: 50%; transform: translateX(-50%);
        width: var(--tail-w); height: var(--tail-h);
        background: linear-gradient(180deg, rgba(255,255,255,0) 0%, rgba(255,255,255,0.7) 80%, rgba(255,255,255,0.9) 100%);
