    .wiped-fx { animation: wipe-away 0.3s ease-out forwards !important; pointer-events: none;}

    @keyframes splatter-in { 0% { transform: scale(0.2) rotate(var(--in-rot)); opacity: 0; } 50% { transform: scale(1.1) rotate(var(--in-rot)); opacity: 0.9; } 100% { transform: scale(1) rotate(var(--fin-rot)); opacity: 0.85; } }
    /* 💦 黏稠挂壁化改写：到底部后保持半透明停留，不再自动消失 */
    @keyframes drip-down { 0% { top: var(--start-y); opacity: 0.85; transform: scaleX(1) scaleY(1); } 80% { opacity: 0.8; transform: scaleX(0.9) scaleY(1.2); } 100% { top: var(--end-y); opacity: 0; transform: scaleX(0.8) scaleY(1.5); } }
    @keyframes wipe-away { 0% { transform: scale(1); filter: blur(0px); opacity: 0.85; } 100% { transform: scale(1.5) translate(var(--wipe-x, 10px), var(--wipe-y, 10px)); filter: blur(10px); opacity: 0; } }

