    @keyframes angel-wing-unfurl {
        0% { opacity: 0; transform: scaleX(0); }
        60% { transform: scaleX(1.05); opacity: 0.6; }
        100% { transform: scaleX(1); opacity: 0.5; }
    }
    .angel-halo.leaving, .angel-feather.leaving, .angel-ray.leaving,
    .angel-wing-l.leaving, .angel-wing-r.leaving {
        animation: angel-leaving 60s ease-in forwards !important;
    }
    @keyframes angel-leaving {
        0% { opacity: 1; transform: translateY(0); }
        100% { opacity: 0; transform: translateY(-30px); }
    }
    .angel-halo {
        position: absolute; top: 5px; left: 50%;
        width: 76px; height: 19px; border-radius: 50%;
        border: 3px solid rgba(255,215,0,0.85);
        transform: translateX(-50%) rotateX(72deg);
        z-index: 15; background: transparent;
        animation: angel-halo-float 3s ease-in-out infinite, angel-halo-glow 2.5s ease-in-out infinite;
}
    .angel-halo::before {
        content: ''; position: absolute; inset: 3px;
        border-radius: 50%; border: 1px solid rgba(255,245,150,0.4);
    }
    .angel-feather {
        position: absolute; opacity: 0;
        width: 7px; height: 20px;
        background: linear-gradient(180deg, rgba(255,255,255,0.92) 0%, rgba(255,240,150,0.6) 60%, rgba(255,215,0,0.15) 100%);
        border-radius: 50% 50% 40% 40% / 60% 60% 40% 40%;
        animation: angel-feather-fall var(--ff-d, 4.5s) ease-in var(--ff-delay, 0s) infinite;
    }
    .angel-feather::after {
        content: ''; position: absolute; left: 50%; top: 10%;
        width: 1px; height: 78%; background: rgba(255,215,0,0.45);
        transform: translateX(-50%);
    }
    .angel-wing-l {
        position: absolute; top: 18px; right: 4px;
        width: 85px; height: 120px; z-index: 2; opacity: 0;
        background: radial-gradient(ellipse at 82% 28%, rgba(255,250,200,0.45) 0%, rgba(255,215,0,0.14) 40%, transparent 70%);
        clip-path: polygon(100% 0%, 100% 22%, 58% 60%, 78% 100%, 38% 80%, 0% 100%, 10% 50%, 0% 20%);
        transform-origin: right center;
        animation: angel-wing-unfurl 2s ease-out 0.4s forwards;
    }
    .angel-wing-r {
        position: absolute; top: 18px; right: 4px;
        width: 85px; height: 120px; z-index: 2; opacity: 0;
        background: radial-gradient(ellipse at 18% 28%, rgba(255,250,200,0.45) 0%, rgba(255,215,0,0.14) 40%, transparent 70%);
        clip-path: polygon(0% 0%, 0% 22%, 42% 60%, 22% 100%, 62% 80%, 100% 100%, 90% 50%, 100% 20%);
        transform-origin: left center;
        animation: angel-wing-unfurl 2s ease-out 0.6s forwards;
    }
    .angel-ray {
        position: absolute; top: 0; left: 50%;
        width: 2px; height: 100%;
        background: linear-gradient(180deg, rgba(255,235,100,0.55) 0%, transparent 100%);
        transform: translateX(-50%);
        animation: angel-ray 3.2s ease-in-out infinite;
    }

    /* ──────────────────────────────── */
    /* 4. 魅魔类                        */
    /* ──────────────────────────────── */
    @keyframes succubus-wing-l {
        0%,100% { transform: scaleX(1) rotate(-5deg); }
        50% { transform: scaleX(0.85) rotate(-18deg); }
    }
    @keyframes succubus-wing-r {
        0%,100% { transform: scaleX(-1) rotate(-5deg); }
        50% { transform: scaleX(-0.85) rotate(-18deg); }
    }
    @keyframes succubus-heart {
        0% { transform: translate(var(--hx),110%) scale(0.3); opacity: 0; }
        12% { opacity: 0.9; }
        88% { opacity: 0.75; }
        100% { transform: translate(var(--hx),-15%) scale(1); opacity: 0; }
    }
    @keyframes succubus-ring-spin {
        0% { transform: translate(-50%,-50%) rotate(0deg); }
        100% { transform: translate(-50%,-50%) rotate(360deg); }
    }
    @keyframes succubus-chain {
        0%,100% { transform: rotate(-9deg); transform-origin: top center; }
        50% { transform: rotate(9deg); transform-origin: top center; }
    }
    @keyframes succubus-leaving {
        0% { opacity: 1; transform: translateY(0) scale(1); }
        100% { opacity: 0; transform: translateY(20px) scale(0.8); }
    }
    .succubus-wing-l-el {
        position: absolute; bottom: 0; left: -18px;
        width: 78px; height: 135px; z-index: 2;
        background: radial-gradient(ellipse at 80% 20%, rgba(180,0,100,0.5) 0%, rgba(80,0,50,0.28) 50%, transparent 75%);
        clip-path: polygon(100% 40%, 80% 0%, 40% 15%, 0% 5%, 15% 40%, 0% 80%, 30% 100%, 70% 80%, 100% 100%);
        transform-origin: bottom right;
        animation: succubus-wing-l 2.5s ease-in-out infinite;
    }
    .succubus-wing-r-el {
        position: absolute; bottom: 0; right: -18px;
        width: 78px; height: 135px; z-index: 2;
        background: radial-gradient(ellipse at 20% 20%, rgba(180,0,100,0.5) 0%, rgba(80,0,50,0.28) 50%, transparent 75%);
        clip-path: polygon(0% 40%, 20% 0%, 60% 15%, 100% 5%, 85% 40%, 100% 80%, 70% 100%, 30% 80%, 0% 100%);
        transform-origin: bottom left;
        animation: succubus-wing-r 2.5s ease-in-out infinite 0.35s;
    }
    .succubus-heart-el {
        position: absolute; bottom: 0; opacity: 0;
        font-size: 11px; color: rgba(240,100,160,0.85);
        text-shadow: 0 0 5px rgba(240,100,160,0.6);
        animation: succubus-heart var(--hd,3.5s) ease-in var(--hdelay,0s) infinite;
    }
    .succubus-ring-el {
        position: absolute; top: 50%; left: 50%;
        width: 155px; height: 155px;
        border: 1px solid rgba(180,0,120,0.22);
        border-radius: 50%; z-index: 1;
        animation: succubus-ring-spin 13s linear infinite;
    }
    .succubus-ring-el::before {
        content: ''; position: absolute; inset: 8px;
        border: 1px dashed rgba(240,100,160,0.18); border-radius: 50%;
    }
    .succubus-chain-el {
        position: absolute; z-index: 4; width: 2px;
        background: repeating-linear-gradient(180deg, rgba(180,0,100,0.6) 0px, rgba(180,0,100,0.6) 4px, rgba(240,100,160,0.35) 4px, rgba(240,100,160,0.35) 6px);
        border-radius: 1px; top: 0;
        animation: succubus-chain 3.2s ease-in-out infinite;
        transform-origin: top center;
    }
    .succubus-wing-l-el.leaving, .succubus-wing-r-el.leaving,
    .succubus-heart-el.leaving, .succubus-ring-el.leaving,
    .succubus-chain-el.leaving {
        animation: succubus-leaving 60s ease-in forwards !important;
    }

    /* ──────────────────────────────── */
    /* 5. 吸血鬼/西幻类                 */
    /* ──────────────────────────────── */
    @keyframes vamp-blood-drip {
        0% { height: 0; opacity: 0; }
        8% { opacity: 1; }
        65% { height: var(--vd-len, 45px); }
        85% { height: var(--vd-len, 45px); opacity: 0.85; }
        100% { height: var(--vd-len, 45px); top: var(--vd-end, 20px); opacity: 0; }
    }
    @keyframes vamp-moon-glow {
        0%,100% { box-shadow: 0 0 12px rgba(200,0,0,0.45), 0 0 28px rgba(150,0,0,0.2); }
        50% { box-shadow: 0 0 22px rgba(220,30,0,0.65), 0 0 48px rgba(180,0,0,0.35); }
    }
    @keyframes vamp-bat {
        0% { transform: translate(var(--bx0),var(--by0)) scale(0.6) rotate(-12deg); opacity: 0; }
        10% { opacity: 0.8; }
        50% { transform: translate(var(--bx1),var(--by1)) scale(1) rotate(5deg); }
        90% { opacity: 0.55; }
        100% { transform: translate(var(--bx2),var(--by2)) scale(0.5) rotate(18deg); opacity: 0; }
    }
    @keyframes vamp-crack {
        0% { opacity: 0; stroke-dashoffset: 220; }
        100% { opacity: 0.58; stroke-dashoffset: 0; }
    }
    @keyframes vamp-leaving {
        0% { opacity: 1; }
        100% { opacity: 0; filter: saturate(0) brightness(0.3); }
    }
    .vamp-blood-moon {
        position: absolute; top: 5px; right: 12px;
        width: 34px; height: 34px; border-radius: 50%;
        background: radial-gradient(circle at 40% 35%, rgba(255,80,60,0.92) 0%, rgba(180,0,0,0.88) 50%, rgba(80,0,0,0.92) 100%);
        z-index: 15;
        animation: vamp-moon-glow 3.2s ease-in-out infinite;
    }
    .vamp-drip-el {
        position: absolute; top: 0; width: 3px; z-index: 5;
        background: linear-gradient(180deg, rgba(180,0,0,0.92) 0%, rgba(120,0,0,0.6) 80%, transparent 100%);
        border-radius: 0 0 2px 2px;
        animation: vamp-blood-drip var(--vdd,4.5s) ease-in var(--vddelay,0s) infinite;
    }
    .vamp-drip-el::after {
        content: ''; position: absolute; bottom: -4px; left: 50%;
        transform: translateX(-50%); width: 7px; height: 7px;
        background: rgba(160,0,0,0.82); border-radius: 50% 50% 60% 60%;
    }
    .vamp-bat-el {
        position: absolute; z-index: 6; opacity: 0; font-size: 13px;
        filter: drop-shadow(0 0 3px rgba(180,0,0,0.55));
        animation: vamp-bat var(--bfd,5s) ease-in-out var(--bfdelay,0s) infinite;
    }
    .vamp-crack-path {
        stroke: rgba(180,0,0,0.52); stroke-width: 1.5;
        fill: none; stroke-dasharray: 220;
        animation: vamp-crack 2s ease-out var(--vc-d,0s) both;
    }
    .vamp-blood-moon.leaving, .vamp-drip-el.leaving,
    .vamp-bat-el.leaving, .vamp-crack-path.leaving {
        animation: vamp-leaving 60s ease-in forwards !important;
    }

    /* ──────────────────────────────── */
    /* 6. 植物类                        */
    /* ──────────────────────────────── */
    @keyframes plant-grow {
        0% { stroke-dashoffset: 500; opacity: 0; }
        18% { opacity: 1; }
        100% { stroke-dashoffset: 0; opacity: 1; }
    }
    @keyframes plant-breathe {
        0%,100% { transform: rotate(-1.5deg) scale(1); transform-origin: bottom left; }
        50% { transform: rotate(1.5deg) scale(1.01); transform-origin: bottom left; }
    }
    @keyframes plant-leaf-unfurl {
        0% { transform: scale(0) rotate(-30deg); opacity: 0; }
        65% { transform: scale(1.12) rotate(5deg); opacity: 0.9; }
        100% { transform: scale(1) rotate(0deg); opacity: 0.85; }
    }
    @keyframes plant-flower-bloom {
        0% { transform: scale(0); opacity: 0; }
        70% { transform: scale(1.2); opacity: 1; }
        100% { transform: scale(1); opacity: 0.92; }
    }
    @keyframes plant-leaving {
        0% { opacity: 1; stroke-dashoffset: 0; }
        60% { stroke: #3a2200; }
        100% { opacity: 0; stroke-dashoffset: 500; stroke: #1a1000; }
    }
    @keyframes plant-leaf-wither {
        0% { opacity: 0.85; transform: scale(1) rotate(0deg); fill: #4a9930; }
        50% { fill: #5a4000; }
        100% { opacity: 0; transform: scale(0.2) rotate(40deg) translateY(10px); fill: #2a1800; }
    }
    .plant-vine {
        fill: none; stroke: #4a9930; stroke-width: 2.2; stroke-linecap: round;
        stroke-dasharray: 500;
        animation: plant-grow 3s cubic-bezier(0.4,0,0.2,1) var(--pv-d,0s) both,
                   plant-breathe 5s ease-in-out infinite calc(3s + var(--pv-d,0s));
    }
    .plant-vine.leaving {
        animation: plant-leaving 60s ease-in forwards !important;
    }
    .plant-vine-thin { stroke: #6ab83a; stroke-width: 1.4; }
    .plant-leaf {
        fill: #4a9930; opacity: 0;
        animation: plant-leaf-unfurl 0.65s ease-out var(--pl-d,2s) both;
    }
    .plant-leaf.leaving {
        animation: plant-leaf-wither 60s ease-in forwards !important;
    }
    .plant-petal { fill: #ff9ec8; opacity: 0; animation: plant-flower-bloom 0.85s ease-out var(--pf-d,3.5s) both; }
    .plant-flower-c { fill: rgba(255,230,100,0.92); opacity: 0; animation: plant-flower-bloom 0.85s ease-out var(--pf-d,3.5s) both; }
    .plant-flower-group {
        animation: plant-flower-bloom 0.85s ease-out var(--pf-d,3.5s) both;
    }
    .plant-flower-group.leaving {
        animation: plant-leaf-wither 60s ease-in forwards !important;
    }

    /* ──────────────────────────────── */
    /* 7. 昆虫类                        */
    /* ──────────────────────────────── */
    @keyframes insect-hex-appear {
        0% { opacity: 0; transform: scale(0.25) rotate(32deg); }
        68% { transform: scale(1.1) rotate(-3deg); }
        100% { opacity: var(--hex-op,0.6); transform: scale(1) rotate(0deg); }
    }
    @keyframes insect-hex-pulse {
        0%,100% { filter: drop-shadow(0 0 1px rgba(200,140,0,0.2)); }
        50% { filter: drop-shadow(0 0 4px rgba(220,170,30,0.55)); }
    }
    @keyframes insect-larva-wriggle {
        0%,100% { transform: scaleX(1) scaleY(1); }
        33% { transform: scaleX(1.09) scaleY(0.92); }
        66% { transform: scaleX(0.93) scaleY(1.08); }
    }
    @keyframes insect-leaving {
        0% { opacity: 1; }
        40% { filter: sepia(1) brightness(0.5); }
        100% { opacity: 0; transform: scale(0.5); }
    }
    .insect-hex-cell {
        animation: insect-hex-appear 0.55s ease-out var(--hex-d,0s) both,
                   insect-hex-pulse 3.2s ease-in-out infinite var(--hex-d,0s);
    }
    .insect-hex-cell.leaving {
        animation: insect-leaving 60s ease-in forwards !important;
    }
    .insect-bug-el {
        position: absolute; font-size: 15px;
        opacity: 0.72; z-index: 5;
        filter: drop-shadow(0 0 2px rgba(200,140,0,0.4)) sepia(0.3);
        animation: insect-larva-wriggle var(--ibw, 1.2s) ease-in-out infinite var(--ibd, 0s);
    }
    .insect-bug-el.leaving {
        animation: insect-leaving 60s ease-in forwards !important;
    }

    /* ──────────────────────────────── */
    /* 8. 野兽类                        */
    /* ──────────────────────────────── */
    @keyframes beast-claw-slash {
        0% { opacity: 0; stroke-dashoffset: 180; }
        35% { opacity: 0.78; stroke-dashoffset: 0; }
        100% { opacity: 0.58; stroke-dashoffset: 0; }
    }
    @keyframes beast-paw-swipe {
        0% { transform: translate(-55px,-18px) rotate(28deg); opacity: 0; }
        18% { opacity: 0.88; }
        62% { transform: translate(8px,4px) rotate(-5deg); opacity: 0.78; }
        100% { transform: translate(18px,10px) rotate(-10deg); opacity: 0; }
    }
    @keyframes beast-fur-ripple {
        0%,100% { opacity: 0.1; }
        50% { opacity: 0.2; }
    }
    @keyframes beast-leaving {
        0% { opacity: 1; }
        100% { opacity: 0; filter: blur(3px); }
    }
    .beast-claw-path {
        stroke: rgba(160,20,20,0.88); stroke-width: 1.2;
        stroke-linecap: butt; fill: none;
        stroke-dasharray: 180;
        animation: beast-claw-slash 0.45s cubic-bezier(0.2,0,0.2,1) var(--bc-d,0s) both;
        filter: drop-shadow(0 0 3px rgba(180,0,0,0.7)) drop-shadow(0 0 8px rgba(120,0,0,0.4));
    }
    .beast-claw-path.leaving {
        animation: beast-leaving 60s ease-in forwards !important;
    }
    .beast-paw-el {
        position: absolute; font-size: 30px; opacity: 0; z-index: 5;
        filter: drop-shadow(0 0 4px rgba(80,40,0,0.5));
        animation: beast-paw-swipe 1.6s ease-out var(--bp-d,0.1s) both;
    }
    .beast-paw-el.leaving {
        animation: beast-leaving 60s ease-in forwards !important;
    }
    .beast-fur-overlay {
        position: absolute; inset: 0; z-index: 1; border-radius: inherit;
        background-image: repeating-linear-gradient(
            125deg,
            transparent 0px, transparent 3px,
            rgba(100,60,10,0.07) 3px, rgba(100,60,10,0.07) 4px
        );
        animation: beast-fur-ripple 4.2s ease-in-out infinite;
    }
    .beast-fur-overlay.leaving {
        animation: beast-leaving 60s ease-in forwards !important;
    }

    /* ──────────────────────────────── */
    /* 9. 史莱姆类                      */
    /* ──────────────────────────────── */
    @keyframes slime-coat-appear {
        0% { opacity: 0; transform: scale(0.93); }
        100% { opacity: 1; transform: scale(1); }
    }
    @keyframes slime-jelly-bounce {
        0%,100% { transform: scale(1,1); }
        30% { transform: scale(1.07,0.94); }
        65% { transform: scale(0.96,1.05); }
    }
    @keyframes slime-blob-morph {
        0%,100% { border-radius: 60% 40% 55% 45% / 50% 60% 40% 50%; transform: translate(0,0) scale(1); }
        25% { border-radius: 40% 60% 45% 55% / 60% 40% 60% 40%; transform: translate(3px,-4px) scale(1.03); }
        50% { border-radius: 55% 45% 60% 40% / 45% 55% 45% 55%; transform: translate(-2px,3px) scale(0.97); }
        75% { border-radius: 45% 55% 40% 60% / 55% 45% 55% 45%; transform: translate(4px,2px) scale(1.02); }
    }
    @keyframes slime-drip-wall {
        0% { height: 0; opacity: 0.85; border-radius: 50% 50% 45% 45%; }
        65% { height: var(--sdl,40px); border-radius: 30% 30% 45% 45%; }
        85% { height: var(--sdl,40px); opacity: 0.7; }
        100% { height: 0; opacity: 0; border-radius: 50%; transform: translateY(var(--sdt,35px)); }
    }
    @keyframes slime-bubble-rise {
        0% { transform: translate(var(--sbx,0px),110%) scale(0.5); opacity: 0.75; }
        100% { transform: translate(var(--sbx,0px),-18%) scale(1); opacity: 0; }
    }
    @keyframes slime-leaving {
        0% { opacity: 1; transform: scale(1); }
        50% { transform: scale(1.05,0.6); }
        100% { opacity: 0; transform: scale(0,0) translateY(20px); }
    }
    .slime-border-coat {
        position: absolute; inset: 0; z-index: 4; border-radius: 16px;
        border: 9px solid rgba(230,120,210,0.45);
        box-shadow: inset 0 0 18px rgba(230,120,210,0.25), 0 0 12px rgba(230,120,210,0.2);
        background: transparent;
        -webkit-mask: linear-gradient(#fff 0 0) padding-box, linear-gradient(#fff 0 0);
        -webkit-mask-composite: destination-out; mask-composite: exclude;
        animation: slime-coat-appear 1.5s ease-out forwards,
                   slime-jelly-bounce 3.2s ease-in-out infinite 1.5s;
    }
    .slime-border-coat.leaving {
        animation: slime-leaving 60s ease-in forwards !important;
    }
    .slime-blob-el {
        position: absolute; z-index: 4;
        background: rgba(230,120,210,0.32);
        backdrop-filter: blur(2px);
        border: 1px solid rgba(250,180,235,0.4);
        animation: slime-blob-morph var(--sbspd,4s) ease-in-out infinite;
    }
    .slime-blob-el.leaving { animation: slime-leaving 60s ease-in forwards !important; }
    .slime-drip-el {
        position: absolute; top: 0; z-index: 6;
        background: linear-gradient(180deg, rgba(230,120,210,0.82) 0%, rgba(200,80,185,0.5) 70%, rgba(200,80,185,0) 100%);
        border-radius: 0 0 50% 50%;
        animation: slime-drip-wall var(--sdd,3.5s) ease-in-out var(--sddelay,0s) infinite;
    }
    .slime-drip-el.leaving { animation: slime-leaving 60s ease-in forwards !important; }
    .slime-bubble-el {
        position: absolute; z-index: 7; border-radius: 50%;
        background: radial-gradient(circle at 35% 30%, rgba(255,220,245,0.82) 0%, rgba(220,120,205,0.3) 60%, transparent 100%);
        border: 1px solid rgba(240,160,225,0.5);
        animation: slime-bubble-rise var(--sbspd,3.5s) ease-in var(--sbdelay,0s) infinite;
    }
    .slime-bubble-el.leaving { animation: slime-leaving 60s ease-in forwards !important; }

    /* ──────────────────────────────── */
    /* 10. 灵体/魔幻类                  */
    /* ──────────────────────────────── */
    @keyframes spirit-wisp-float {
        0% { transform: translate(var(--wx0),var(--wy0)) scale(0.6); opacity: 0; }
        14% { opacity: var(--wisp-op,0.75); }
        50% { transform: translate(var(--wx1),var(--wy1)) scale(1); }
        86% { opacity: var(--wisp-op,0.75); }
        100% { transform: translate(var(--wx2),var(--wy2)) scale(0.5); opacity: 0; }
    }
    @keyframes spirit-ripple {
        0% { transform: translate(-50%,-50%) scale(0); opacity: 0.55; }
        100% { transform: translate(-50%,-50%) scale(2.6); opacity: 0; }
    }
    @keyframes spirit-ecto-drip {
        0% { transform: scaleY(0) translateY(0); opacity: 0.8; transform-origin: top; }
        62% { transform: scaleY(1) translateY(0); opacity: 0.48; transform-origin: top; }
        100% { transform: scaleY(1) translateY(var(--ed,55px)); opacity: 0; transform-origin: top; }
    }
    @keyframes spirit-rune-glow {
        0%,100% { opacity: 0.18; }
        50% { opacity: 0.52; filter: drop-shadow(0 0 4px rgba(0,200,160,0.55)); }
    }
    @keyframes spirit-phantom-hand {
        0% { opacity: 0; transform: translateY(20px) scale(0.8); }
        28% { opacity: 0.48; transform: translateY(0) scale(1); }
        72% { opacity: 0.4; transform: translateY(-5px) scale(1.02); }
        100% { opacity: 0; transform: translateY(-16px) scale(0.88); }
    }
    @keyframes spirit-leaving {
        0% { opacity: 1; filter: blur(0px); }
        100% { opacity: 0; filter: blur(8px); }
    }
    .spirit-wisp-el {
        position: absolute; z-index: 6; opacity: 0; border-radius: 50%;
        background: radial-gradient(circle at 40% 35%, rgba(160,255,230,0.92) 0%, rgba(0,200,160,0.5) 40%, rgba(0,150,120,0.18) 70%, transparent 100%);
        filter: blur(2px);
        animation: spirit-wisp-float var(--wspd,5.5s) ease-in-out var(--wdelay,0s) infinite;
    }
    .spirit-wisp-el::before {
        content: ''; position: absolute; inset: 20%; border-radius: 50%;
        background: rgba(200,255,245,0.62); filter: blur(3px);
    }
    .spirit-wisp-el.leaving { animation: spirit-leaving 60s ease-in forwards !important; }
    .spirit-ripple-el {
