    .vw-label {
        position: absolute; left: 8px;
        font-family: monospace; font-size: 0.48rem;
        font-weight: 900; letter-spacing: 1px;
        z-index: 12; pointer-events: none;
    }
    .vw-wave-box {
        position: absolute; left: 44px; right: 0; height: 100%;
        overflow: hidden;
    }
    .vw-line {
        position: absolute; width: 200%; height: 100%;
        background-repeat: repeat-x; background-size: contain; background-position: left center;
        mask-image: linear-gradient(90deg, transparent 0%, black 8%, black 100%);
        -webkit-mask-image: linear-gradient(90deg, transparent 0%, black 8%, black 100%);
        will-change: transform;
    }
    .vw-overlay {
        position: absolute; width: 200%; height: 100%;
        background-repeat: repeat-x; background-size: contain; background-position: left center;
        opacity: 0.32; mix-blend-mode: screen; pointer-events: none;
        mask-image: linear-gradient(90deg, transparent 0%, black 8%, black 100%);
        -webkit-mask-image: linear-gradient(90deg, transparent 0%, black 8%, black 100%);
    }

