    /* ══════*/
    /* 🌈 智能进度条系统：渐变色 + 满值特效 (Gradient Bar Engine) */
    /* ══════*/

    /* ── 进度条箭头（仅数值变化时由JS添加 data-changed="1" 显示） ── */
    .bar-arrow { font-size: 0.72em; display: none; }
    .bar-row-wrap[data-changed="1"] .bar-arrow { display: inline; }
    .arrow-up   { color: #ff7eb3; }
    .arrow-down { color: #a2e1db; }

    /* ── 满值特效公共容器（绝对定位于 .bar-row-wrap，脱离overflow限制） ── */
    .full-fx {
        position: absolute;
        top: 50%; transform: translateY(-50%);
        pointer-events: none; display: none;
        align-items: center; z-index: 20;
    }
    .bar-row-wrap.is-full .full-fx { display: flex; }

    /* ── 1. 发情值 玫红→珊瑚→蜜橙 ── */
    .bf-estrous {
        background: linear-gradient(90deg, #ff6b9d 0%, #ff9f7f 60%, #ffcba4 100%);
        box-shadow: 0 0 5px rgba(255,107,157,0.4);
    }
    .bar-row-wrap.br-estrous { border-left-color: #ff6b9d !important; }
    /* 满值红温警报：进度条闪烁发红 */
    .bar-row-wrap.br-estrous.is-full .bar-fill {
        background: linear-gradient(90deg, #ff6b9d 0%, #ff1e6a 60%, #ff0000 100%) !important;
        animation: tf-alert 0.4s steps(2, start) infinite;
    }
    .fx-alert-max {
        position: absolute; right: -28px; top: 50%; /* 悬浮在右侧 */
        color: #ff1e6a; font-family: monospace; font-size: 0.8em; font-weight: 900;
        text-shadow: 0 0 8px #ff1e6a, 0 0 12px #fff;
        animation: tf-alert-text 2.2s cubic-bezier(0.4, 0, 1, 1) infinite;
        pointer-events: none; white-space: nowrap;
    }
    @keyframes tf-alert {
        0% { box-shadow: 0 0 15px rgba(255,30,106,0.6); }
        100% { box-shadow: 0 0 30px rgba(255,30,106,0.9), inset -10px 0 15px #ff1e6a; }
    }
    @keyframes tf-alert-text {
        0% { transform: scale(1) translate(0, -50%) rotate(5deg); opacity: 1; filter: blur(0px); }
        50% { transform: scale(1.4) translate(4px, calc(-50% - 2px)) rotate(12deg); opacity: 0.6; filter: blur(1px);}
        100% { transform: scaleX(1.8) scaleY(0.8) translate(8px, calc(-50% + 2px)) rotate(8deg); opacity: 0; filter: blur(2px); }
    }
    /* ── 2. 淫乱值 深玫→亮粉→薄荷白 ── */
    .bf-lewd {
        background: linear-gradient(90deg, #c94b8c 0%, #ff7eb3 65%, #ffe0ef 100%);
        box-shadow: 0 0 5px rgba(201,75,140,0.4);
    }
    .bar-row-wrap.br-lewd { border-left-color: #c94b8c !important; }
    /* 满值液滴 */
    .fx-lewd-drop {
        width:5px; height:5px; border-radius:50%;
        background:#ff7eb3; box-shadow:0 0 5px rgba(255,126,179,0.8);
        animation: lewd-drip 1.7s ease-in infinite;
    }
    .fx-lewd-drop-b { animation-delay:0.85s; margin-left:4px; }
    @keyframes lewd-drip {
        0%   { transform:translateY(0) scale(1.2,.8); opacity:.9; }
        20%  { transform:translateY(3px) scale(.9,1.1); opacity:1; }
        70%  { transform:translateY(16px) scale(.85,1); opacity:.55; }
        100% { transform:translateY(23px) scale(.5); opacity:0; }
    }

    /* ── 3. 雌堕值 暗紫→洋红→玫粉 ── */
    .bf-deprave {
        background: linear-gradient(90deg, #7c2d8c 0%, #d1477a 60%, #ffb3c6 100%);
        box-shadow: 0 0 5px rgba(209,71,122,0.4);
    }
    .bar-row-wrap.br-deprave { border-left-color: #7c2d8c !important; }
    /* 满值爱心 */
    .bar-row-wrap.br-deprave.is-full .bar-wrap-inner {
        animation: flame-border 0.65s ease-in-out infinite alternate;
    }
    @keyframes flame-border {
        0%   { box-shadow: 0 0 3px rgba(255,30,106,.25); }
        100% { box-shadow: 0 0 10px rgba(255,30,106,.75), inset 0 0 5px rgba(255,30,106,.2); }
    }
    .fx-heart {
        font-size:11px; color:#ff4d8c;
        text-shadow: 0 0 5px rgba(255,77,140,.8);
        animation: heart-beat 0.7s ease-in-out infinite alternate;
        line-height:1;
    }
    @keyframes heart-beat {
        0%   { transform: scale(.7) translateY(0); opacity:.55; }
        100% { transform: scale(1.35) translateY(-3px); opacity:1; filter:drop-shadow(0 0 4px #ff1e6a); }
    }

    /* ── 4a. 理智值（正常）粉红→薰衣草→冰蓝 ── */
    .bf-sanity {
        background: linear-gradient(90deg, #ff7eb3 0%, #b39ddb 50%, #7de8f0 100%);
        box-shadow: 0 0 3px rgba(125,232,240,.15);
        overflow: hidden;
}
    .bar-row-wrap.br-sanity { border-left-color: #7de8f0 !important; }
    /* 冰晶扫光（bar内部::before，用JS动态给fill加class） */
    .bf-sanity.full::before {
        content:''; position:absolute; top:0; bottom:0; left:-55%;
        width:45%; border-radius:20px;
        background: linear-gradient(90deg, transparent, rgba(255,255,255,.72), transparent);
        animation: ice-shimmer 2.6s ease-in-out infinite;
    }
    @keyframes ice-shimmer { 0%{left:-55%} 58%{left:110%} 100%{left:110%} }

    /* ── 4b. 理智值（≤20危机）碎裂亮度呼吸 ── */
    .bf-sanity-low {
        background: linear-gradient(90deg, #c00040 0%, #ff1e6a 45%, #ffb3c6 100%);
        box-shadow: 0 0 5px rgba(255,30,106,.5);
        overflow: hidden;
        animation: sanity-crack 2.8s ease-in-out infinite alternate;
    }
    @keyframes sanity-crack {
        0%   { filter:brightness(.65) saturate(.8); box-shadow:0 0 2px rgba(255,30,106,.3); }
        35%  { filter:brightness(1.5) saturate(1.3); box-shadow:0 0 14px rgba(255,30,106,.9), inset 0 0 7px rgba(255,255,255,.3); }
        68%  { filter:brightness(.45) saturate(.6); box-shadow:0 0 2px rgba(100,0,30,.4); }
        100% { filter:brightness(1.7) saturate(1.6); box-shadow:0 0 20px rgba(255,30,106,1), inset 0 0 10px rgba(255,200,200,.4); }
    }

    /* ── 5. 服从度 酒红→暗玫→苍金 ── */
    .bf-obey {
        background: linear-gradient(90deg, #5c0a28 0%, #a0274f 50%, #c8a96e 100%);
        box-shadow: 0 0 5px rgba(160,39,79,.45);
    }
    .bar-row-wrap.br-obey { border-left-color: #8b1a4a !important; }

    @keyframes obey-tremble {
        0%,100% { transform:translateX(0); }
        20%     { transform:translateX(-1.5px); }
        45%     { transform:translateX(2px); }
        70%     { transform:translateX(-1px); }
        88%     { transform:translateX(1px); }
    }
    .fx-chain {
        font-size:11px; color:#c8a96e;
        text-shadow:0 0 5px rgba(200,169,110,.8);
        animation: chain-rattle .38s ease-in-out infinite alternate;
        line-height:1;
    }
    @keyframes chain-rattle {
        0%   { transform:rotate(-10deg) scale(.85) translateY(1px); opacity:.65; }
        100% { transform:rotate(10deg) scale(1.2) translateY(-2px); opacity:1; filter:drop-shadow(0 0 4px #c8a96e); }
    }

    /* ── 6. 痛转快感度 冰钢白→闪电紫→灼烧橙 ── */
    .bf-pain {
        background: linear-gradient(90deg, #e8f0ff 0%, #9c6fdb 45%, #ff8c42 100%);
        box-shadow: 0 0 6px rgba(156,111,219,.5);
    }
    .bar-row-wrap.br-pain { border-left-color: #9c6fdb !important; }
    /* 满值电弧 */
    .bar-row-wrap.br-pain.is-full .bar-wrap-inner {
        animation: arc-flash .95s steps(1) infinite;
    }
    @keyframes arc-flash {
        0%,100% { box-shadow:none; }
        11%,14% { box-shadow:0 0 10px rgba(156,111,219,.95), inset 0 0 5px rgba(255,255,255,.5); }
        43%,46% { box-shadow:0 0 14px rgba(255,140,66,.85), inset 0 0 6px rgba(255,200,100,.4); }
        70%,73% { box-shadow:0 0 8px rgba(156,111,219,.7); }
    }
    .fx-bolt {
        font-size:12px;
        animation: bolt-pop .95s steps(1) infinite;
        line-height:1;
    }
    @keyframes bolt-pop {
        0%,10%  { opacity:0; transform:scale(.6) translateY(0); }
        11%,14% { opacity:1; transform:scale(1.4) translateY(-4px); filter:drop-shadow(0 0 5px #fff); }
        15%,42% { opacity:0; transform:scale(.6) translateY(0); }
        43%,46% { opacity:1; transform:scale(1.5) translateY(-5px); filter:drop-shadow(0 0 6px #ff8c42); }
        47%,100%{ opacity:0; transform:scale(.6) translateY(0); }
    }

    /* ── 7. 失禁混淆度 薄荷→水蓝→珍珠白 ── */
    .bf-incont {
        background: linear-gradient(90deg, #80deea 0%, #b2f0fb 60%, #f0fdff 100%);
        box-shadow: 0 0 4px rgba(128,222,234,.35);
    }
    .bar-row-wrap.br-incont { border-left-color: #80deea !important; }
    /*数字模糊 */
    .bar-row-wrap.br-incont.is-full { }
    @keyframes incont-shake {
        0%,100% { transform:translateX(0); }
        18%     { transform:translateX(-2px) translateY(.5px); }
        36%     { transform:translateX(2.5px); }
        54%     { transform:translateX(-1.5px) translateY(-.5px); }
        72%     { transform:translateX(1px); }
    }
    .bar-row-wrap.br-incont.is-full .bar-num {
        animation: num-blur 1.9s ease-in-out infinite alternate;
    }
    @keyframes num-blur {
        0%   { filter:blur(0); opacity:1; }
        100% { filter:blur(2.5px); opacity:.6; }
    }

    /* ── 8. 高潮临近度 浅樱→暖粉→珍珠白 ── */
    .bf-climax {
        background: linear-gradient(90deg, #ffb3c6 0%, #ffd6e0 55%, #fff5f7 100%);
        box-shadow: 0 0 5px rgba(255,179,198,.4);
    }
    .bar-row-wrap.br-climax { border-left-color: #ffb3c6 !important; }
    /* 满值白光脉冲 */
    .bar-row-wrap.br-climax.is-full .bar-wrap-inner {
        animation: climax-pulse .55s ease-in-out infinite alternate;
    }
    @keyframes climax-pulse {
        0%   { box-shadow:0 0 3px rgba(255,179,198,.4); }
        100% { box-shadow:0 0 18px rgba(255,255,255,.9), 0 0 8px rgba(255,100,140,.7); }
    }
    .bf-climax.full { animation: climax-fill-flash .55s ease-in-out infinite alternate; }
    @keyframes climax-fill-flash {
        0%   { filter:brightness(1); }
        100% { filter:brightness(1.9) saturate(.4); }
    }
    .fx-climax-stars {
        color: #ffb3c6;
        font-size: 1.1rem;
        font-weight: bolder;
        letter-spacing: -2px;
        text-shadow: 0 0 5px #fff, 0 0 10px #ff7eb3;
        animation: tf-star-burst 0.8s ease-out infinite;
        white-space: nowrap;
        line-height: 1;
        pointer-events: none;
    }
    @keyframes tf-star-burst {
        0% { transform: translate(-8px, 0) scale(0.5) rotate(-20deg); opacity: 1; filter: blur(0px); }
        60% { transform: translate(10px, -5px) scale(1.3) rotate(15deg); opacity: 0.9; text-shadow: 0 0 8px #fff, 0 0 15px #ff7eb3; }
        100% { transform: translate(15px, -10px) scale(1.5) rotate(30deg); opacity: 0; filter: blur(1.5px); text-shadow: 0 0 20px #ff1e6a; }
    }
    /* ── 9. 淫水失控 冰蓝→水蓝→薄荷白 ── */
    .bf-fluid {
        background: linear-gradient(90deg, #29b6f6 0%, #80deea 55%, #e0f7fa 100%);
        box-shadow: 0 0 5px rgba(41,182,246,.4);
    }
    .bar-row-wrap.br-fluid { border-left-color: #29b6f6 !important; }
    /* 满值蓝色水滴 */
    .fx-fluid-drop {
        width:5px; height:5px; border-radius:50%;
        background: radial-gradient(circle at 35% 30%, #e0f7fa, #29b6f6);
        box-shadow:0 0 5px rgba(41,182,246,.8);
        animation: fluid-drip 2.5s cubic-bezier(.4,0,.8,1) infinite;
    }
    .fx-fluid-drop-b { animation-delay:1.25s; margin-left:4px; }
    @keyframes fluid-drip {
        0%   { transform:translateY(0) scale(1.1,.9); opacity:.9; }
        15%  { transform:translateY(2px) scale(.9,1.1); opacity:1; }
        65%  { transform:translateY(14px) scale(.85,1); opacity:.6; }
        100% { transform:translateY(22px) scale(.5); opacity:0; }
    }

    /* ── 10. 母性淫性混淆 薰衣草紫→婴儿粉→月光白 ── */
    .bf-maternal {
        background: linear-gradient(90deg, #b39ddb 0%, #f48fb1 55%, #fce4ec 100%);
        box-shadow: 0 0 4px rgba(179,157,219,.4);
        overflow: hidden;
    }
    .bar-row-wrap.br-maternal { border-left-color: #b39ddb !important; }
    /* 满值奶白光晕扫过 */
    .bf-maternal.full::before {
        content:''; position:absolute; top:0; bottom:0; left:-60%;
        width:55%; border-radius:20px;
        background: linear-gradient(90deg, transparent, rgba(255,240,255,.8), transparent);
        animation: milk-pour 3.2s ease-in-out infinite;
    }
    @keyframes milk-pour {
        0%   { left:-60%; opacity:.5; }
        68%  { left:110%; opacity:.95; }
        100% { left:110%; opacity:0; }
    }
    .fx-maternal-star {
        font-size:10px; color:#d1c4e9;
        text-shadow:0 0 5px rgba(179,157,219,.9);
        animation: maternal-star 1.4s ease-in-out infinite alternate;
        line-height:1;
    }
    @keyframes maternal-star {
        0%   { transform:scale(.7) rotate(-15deg) translateY(1px); opacity:.5; }
        100% { transform:scale(1.3) rotate(20deg) translateY(-3px); opacity:1; filter:drop-shadow(0 0 4px #e1bee7); }
    }

    /* ── 11. 子宫沦陷 暗石榴→铜橙→暖琥珀 ── */
    .bf-womb {
        background: linear-gradient(90deg, #7b1a0a 0%, #c04a1a 45%, #e8943a 75%, #f5d08a 100%);
        box-shadow: 0 0 6px rgba(181,69,27,.5);
    }
    .bar-row-wrap.br-womb { border-left-color: #b5451b !important; }
    /* 满值琥珀脉冲 */
    .bar-row-wrap.br-womb.is-full .bar-wrap-inner {
        animation: womb-throb .72s ease-in-out infinite alternate;
    }
    @keyframes womb-throb {
        0%   { box-shadow:0 0 3px rgba(181,69,27,.3); border-color:rgba(181,69,27,.3); }
        100% { box-shadow:0 0 14px rgba(232,148,58,.8), inset 0 0 5px rgba(245,208,138,.3); border-color:rgba(232,148,58,.6); }
    }
    .bf-womb.full { animation: womb-fill-pulse .72s ease-in-out infinite alternate; }
    @keyframes womb-fill-pulse {
        0%   { filter:brightness(.82) saturate(1); }
        100% { filter:brightness(1.3) saturate(1.5); }
    }
    .fx-womb-ember {
        font-size:10px; color:#f5d08a;
        text-shadow:0 0 5px rgba(232,148,58,.9);
        animation: ember-flicker .72s ease-in-out infinite alternate;
        line-height:1;
    }
    @keyframes ember-flicker {
        0%   { transform:scale(.75) translateY(2px); opacity:.55; }
        100% { transform:scale(1.3) translateY(-4px); opacity:1; filter:drop-shadow(0 0 5px #e8943a); }
    }

    /* ── 12. 孕期超敏 浅粉→淡紫→薄荷 ── */
    .bf-pregsen {
        background: linear-gradient(90deg, #f8c8d8 0%, #ce93d8 50%, #b2ebf2 100%);
        box-shadow: 0 0 5px rgba(206,147,216,.4);
    }
    .bar-row-wrap.br-pregsen { border-left-color: #ce93d8 !important; }
    .bf-pregsen.full { animation: pregsen-breath 1.9s ease-in-out infinite alternate; }
    @keyframes pregsen-breath {
        0%   { filter:brightness(.88) saturate(.9); }
        100% { filter:brightness(1.28) saturate(1.25); }
    }
    .fx-pregsen-dot {
        width:7px; height:7px; border-radius:50%;
        background: linear-gradient(135deg, #f8c8d8, #b2ebf2);
        box-shadow:0 0 5px rgba(206,147,216,.7);
        animation: pregsen-dot-pulse 1.9s ease-in-out infinite alternate;
    }
    @keyframes pregsen-dot-pulse {
        0%   { transform:scale(.7); opacity:.5; }
        100% { transform:scale(1.3); opacity:1; filter:drop-shadow(0 0 5px #ce93d8); }
    }

    /* ── 13. 胎内浊化 星云紫蓝→玫瑰粉→珍珠白 柔美清透版 ── */
    .bf-contaminate {
        background: linear-gradient(90deg, #c5caf5 0%, #e8a4c8 50%, #fde8f0 100%);
        box-shadow: 0 0 5px rgba(197,202,245,.5);
    }
    .bar-row-wrap.br-contaminate { border-left-color: #a8aee8 !important; }
    /* 满值：柔和流光扫过 */
    .bf-contaminate.full { overflow:hidden; }
    .bf-contaminate.full::after {
        content:''; position:absolute; inset:0;
        background: repeating-linear-gradient(
            90deg,
            rgba(220,210,255,.18) 0px, rgba(220,210,255,.18) 8px,
            transparent 8px, transparent 16px
        );
        background-size:200% 100%;
        animation: contaminate-shimmer 3.5s linear infinite;
        border-radius:20px; mix-blend-mode:overlay;
    }
    @keyframes contaminate-shimmer {
        0%   { background-position:100% 0; }
        100% { background-position:-100% 0; }
    }
    .fx-contaminate-orb {
        width:7px; height:7px; border-radius:50%;
        background: radial-gradient(circle at 35% 30%, #fde8f0, #c5caf5);
        box-shadow:0 0 5px rgba(197,202,245,.8);
        animation: contam-pulse 2.8s ease-in-out infinite alternate;
    }
    @keyframes contam-pulse {
        0%   { transform:scale(.7); opacity:.45; filter:hue-rotate(0deg); }
        100% { transform:scale(1.3); opacity:1; filter:hue-rotate(20deg) drop-shadow(0 0 4px #e8a4c8); }
    }
    /* ── 悬赏任务板三态 ── */
    .bounty-item-cyber {
        display: flex; align-items: center; gap: 8px;
        padding: 7px 10px;
        border-bottom: 1px solid rgba(255,255,255,0.04);
        cursor: pointer;
        transition: background 0.2s, opacity 0.3s;
        position: relative; overflow: hidden;
        user-select: none; -webkit-user-select: none;
    }
    .bounty-item-cyber:last-child { border-bottom: none; }
    .bounty-item-cyber:active { background: rgba(255,255,255,0.03); }

    .bounty-item-cyber .b-rank {
        font-family: monospace; font-size: 0.65em; font-weight: 900;
        padding: 1px 5px; border-radius: 5px;
        flex-shrink: 0; letter-spacing: 0.5px;
        transition: all 0.3s;
    }
    .bounty-item-cyber .rank-S { color: #f0abfc; border: 1px solid rgba(240,171,252,0.6); background: rgba(240,171,252,0.08); }
    .bounty-item-cyber .rank-A { color: #67e8f9; border: 1px solid rgba(103,232,249,0.5); background: rgba(103,232,249,0.07); }
    .bounty-item-cyber .rank-B { color: #a5b4fc; border: 1px solid rgba(165,180,252,0.45); background: rgba(165,180,252,0.06); }

    .bounty-item-cyber .b-body { flex: 1; overflow: hidden; min-width: 0; }
    .bounty-item-cyber .b-desc {
        font-size: 0.78em; font-weight: 700; color: #dde8f8;
        line-height: 1.35; display: flex; align-items: center; gap: 4px;
        transition: all 0.3s;
    }
    .bounty-item-cyber .b-icon { font-size: 0.9em; flex-shrink: 0; transition: all 0.3s; }
    .bounty-item-cyber .b-reward {
        font-family: monospace; font-size: 0.7em; font-weight: 900;
        flex-shrink: 0; padding: 2px 6px; border-radius: 6px;
        transition: all 0.3s; white-space: nowrap;
    }
    .bounty-item-cyber .rank-S-reward { color: #f0abfc; background: rgba(240,171,252,0.1); border: 1px solid rgba(240,171,252,0.25); }
    .bounty-item-cyber .rank-A-reward { color: #67e8f9; background: rgba(103,232,249,0.08); border: 1px solid rgba(103,232,249,0.2); }
    .bounty-item-cyber .rank-B-reward { color: #a5b4fc; background: rgba(165,180,252,0.08); border: 1px solid rgba(165,180,252,0.18); }

/* 已接受 */
.bounty-item-cyber.b-accepted {
    background: rgba(255,200,80,0.04);
    border-bottom-color: rgba(255,200,80,0.1);
    pointer-events: none;
}
    .bounty-item-cyber.b-accepted::before {
        content: ''; position: absolute; inset: 0;
        border: 1px dashed rgba(255,200,80,0.45); pointer-events: none;
        animation: b-dash-march 8s linear infinite;
    }
    @keyframes b-dash-march { 0%,100%{border-color:rgba(255,200,80,0.4)} 50%{border-color:rgba(255,200,80,0.75)} }
    .bounty-item-cyber.b-accepted .b-desc { color: #fde68a; }
    .bounty-item-cyber.b-accepted .b-rank { color: #fde68a !important; border-color: rgba(253,230,138,0.5) !important; background: rgba(253,230,138,0.08) !important; }
    .bounty-item-cyber.b-accepted .b-reward { color: #fde68a !important; border-color: rgba(253,230,138,0.3) !important; background: rgba(253,230,138,0.07) !important; }

    /* 已完成 */
    .bounty-item-cyber.b-done { opacity: 0.35; cursor: default; }
    .bounty-item-cyber.b-done .b-desc { text-decoration: line-through; color: #6a7a8a; }
    .bounty-item-cyber.b-done .b-rank,
    .bounty-item-cyber.b-done .b-reward { opacity: 0.35; }
    .bounty-item-cyber.b-done:active { background: transparent; }

    /* 消失动画 */
    .bounty-item-cyber.b-dissolving {
        animation: b-dissolve 0.6s ease-out forwards;
    }
    @keyframes b-dissolve {
        0%   { opacity:0.35; max-height:80px; padding-top:7px; padding-bottom:7px; }
        60%  { opacity:0; max-height:80px; }
        100% { opacity:0; max-height:0; padding-top:0; padding-bottom:0; overflow:hidden; }
    }

    /* 涟漪 */
    .b-ripple-el {
        position: absolute; border-radius: 50%;
        background: rgba(255,255,255,0.1); pointer-events: none;
        transform: scale(0); animation: b-ripple-go 0.5s ease-out forwards;
    }
    @keyframes b-ripple-go { 0%{transform:scale(0);opacity:1} 100%{transform:scale(4);opacity:0} }

    /* ── 赎买：余额不足抖动 ── */
    .buyback-card.no-cash {
        animation: bb-reject 0.42s ease !important;
        border-color: rgba(255,80,100,0.8) !important;
        box-shadow: 0 0 12px rgba(255,80,100,0.35) !important;
    }
    @keyframes bb-reject {
        0%,100%{transform:translateX(0)}
        20%{transform:translateX(-5px)}
        45%{transform:translateX(5px)}
        65%{transform:translateX(-3px)}
        82%{transform:translateX(3px)}
    }

    /* 扣费飞字 */
    .deduct-float-el {
        position: fixed; pointer-events: none; z-index: 9999;
        font-family: monospace; font-size: 0.78em; font-weight: 900;
        color: #f0abfc; text-shadow: 0 0 6px rgba(192,132,252,0.7);
        white-space: nowrap; user-select: none;
        animation: deduct-rise-el 1.1s ease-out forwards;
    }
    @keyframes deduct-rise-el {
        0%  {opacity:1;transform:translate(-50%,-50%) translateY(0) scale(0.9)}
        30% {opacity:1;transform:translate(-50%,-50%) translateY(-10px) scale(1.1)}
        100%{opacity:0;transform:translate(-50%,-50%) translateY(-30px) scale(0.85)}
    }

    /* 赎买：余额条 */
    .buyback-coin-bar {
        display: flex; align-items: center; justify-content: space-between;
        padding: 4px 8px; margin-bottom: 8px;
        background: rgba(255,126,179,0.07);
        border-radius: 7px; border: 1px dashed rgba(255,126,179,0.3);
    }
    .buyback-coin-label { font-size: 0.68em; color: #b07090; font-weight: 700; }
    .buyback-coin-val {
        font-family: monospace; font-size: 0.82em; font-weight: 900;
        color: #ff7eb3; min-width: 55px; text-align: right;
        text-shadow: 0 0 4px rgba(255,126,179,0.3);
        transition: color 0.1s;
    }
    .buyback-coin-val.bb-tick { animation: bb-coin-tick 0.1s ease; }
    @keyframes bb-coin-tick {
        0%,100%{transform:translateY(0) scale(1)}
        50%{transform:translateY(-2px) scale(1.08);color:#c084fc}
    }

    /* 赎买：已兑换状态标记 */
    .buyback-done-badge {
        font-size: 0.7em; font-weight: 900; color: #c084fc;
        opacity: 0; transform: scale(0.6);
        transition: all 0.25s ease; white-space: nowrap;
        display: inline-block; line-height: 1;
    }
    .buyback-card.spent .buyback-done-badge { opacity:1; transform:translateY(0); }
    .buyback-card.spent .buyback-cost { background:rgba(206,147,216,0.08); color:rgba(206,147,216,0.5); border-color:rgba(206,147,216,0.2); }
.buyback-card.spent .buyback-desc { color:rgba(180,140,210,0.45); text-decoration:line-through; opacity:0.65; }
/* ═══ */
/* 🩸 雌堕腐化引擎 (Deprave Corruption Engine)          */
/* ═══ */

/* 边框粉色液滴节点 */
.depr-drip-node {
    position: absolute; top: -1px; width: 4px;
    pointer-events: none; z-index: 201;
}
.depr-drip-node::before {
    content: '';
    position: absolute; top: 0; left: 50%; transform: translateX(-50%);
    width: 3px; height: 0;
    background: linear-gradient(180deg, rgba(255,100,160,0.9), rgba(255,60,130,0.4) 70%, transparent);
    border-radius: 0 0 2px 2px;
    animation: depr-drip-fall var(--dd, 7s) ease-in var(--ddelay, 0s) infinite;
}
.depr-drip-node::after {
    content: '';
    position: absolute; top: 0; left: 50%;
    transform: translateX(-50%);
    width: 5px; height: 5px;
    background: rgba(255,80,140,0.82); border-radius: 50% 50% 60% 60%;
    opacity: 0;
    animation: depr-blob-fall var(--dd, 7s) ease-in var(--ddelay, 0s) infinite;
}
@keyframes depr-drip-fall {
    0%,78%   { height: 0; opacity: 0; }
    80%      { height: 2px; opacity: 0.8; }
    88%      { height: var(--drip-len, 32px); opacity: 0.9; }
    95%,100% { height: 0; opacity: 0; }
}
@keyframes depr-blob-fall {
    0%,86%   { opacity: 0; transform: translateX(-50%) translateY(0) scale(0.5); }
    89%      { opacity: 0.85; transform: translateX(-50%) translateY(var(--drip-len, 32px)) scale(1.1); }
    96%,100% { opacity: 0; transform: translateX(-50%) translateY(calc(var(--drip-len, 32px) + 6px)) scale(0.3); }
}

/* 标题偶发痉挛 - 轻度 */
@keyframes depr-spasm-mild {
    0%,72%,100% { transform: translateX(0) skewX(0deg); filter: blur(0); }
    74% { transform: translateX(-2px) skewX(-1.5deg); }
    76% { transform: translateX(2px) skewX(1deg); filter: blur(0.3px); }
    78% { transform: translateX(-1px); }
    80% { transform: translateX(0); filter: blur(0); }
}
/* 标题偶发痉挛 - 重度 */
@keyframes depr-spasm-heavy {
    0%,65%,100% { transform: translateX(0) skewX(0deg); filter: blur(0); }
    67% { transform: translateX(-3px) skewX(-2.5deg); filter: blur(0.5px); color: #ff1e6a; }
    70% { transform: translateX(3px) skewX(2deg); color: #ffb3c6; }
    72% { transform: translateX(-2px); filter: blur(0.2px); }
    74% { transform: translateX(0); filter: blur(0); }
}

/* Tab按钮腐化：原词变残影，after显示替换词 */
.depr-tab-corrupted {
    color: rgba(255,179,198,0.28) !important;
    border-color: rgba(255,30,106,0.3) !important;
    background: rgba(255,30,106,0.06) !important;
    position: relative;
}
.depr-tab-corrupted .depr-tab-origin {
    opacity: 0.22;
    text-decoration: line-through;
    text-decoration-color: rgba(255,30,106,0.5);
    color: rgba(255,179,198,0.28);
}
.depr-tab-corrupted::after {
    content: attr(data-depr-corrupt);
    position: absolute; inset: 0;
    display: flex; align-items: center; justify-content: center;
    color: #ff6699; font-weight: 900; font-size: 1em;
    text-shadow: 0 0 5px rgba(255,30,106,0.6);
    pointer-events: none;
    animation: depr-tab-flicker 4s ease-in-out infinite;
}
@keyframes depr-tab-flicker {
    0%,82%,100% { opacity: 1; transform: translateX(0); filter: blur(0); }
    84% { opacity: 0.5; transform: translateX(-1px); filter: blur(0.5px); }
    87% { opacity: 1; transform: translateX(0.5px); }
}
/* 点击展开原词 */
.depr-tab-corrupted.depr-reveal::after { display: none; }
.depr-tab-corrupted.depr-reveal .depr-tab-origin {
    opacity: 0.9 !important;
    text-decoration: none !important;
    color: var(--text-sub) !important;
    animation: depr-reveal-glow 0.4s ease-out;
}
@keyframes depr-reveal-glow {
    0% { text-shadow: 0 0 10px rgba(0,245,255,0.8); }
    100% { text-shadow: none; }
}

/* data-key 腐化：原词残影+after替换词 */
.depr-key-corrupted {
    position: relative;
    cursor: pointer;
}
.depr-key-corrupted .depr-kw-origin {
    opacity: 0.22;
    color: var(--kt-cyan-dim) !important;
    text-decoration: line-through;
    text-decoration-color: rgba(255,30,106,0.45);
}
.depr-key-corrupted::after {
    content: attr(data-depr-word);
    position: absolute; left: 0; top: 0;
    color: #ff6699; font-weight: 900;
    text-shadow: 0 0 5px rgba(255,30,106,0.65);
    white-space: nowrap;
    pointer-events: none;
    animation: depr-key-idle 5s ease-in-out infinite;
}
@keyframes depr-key-idle {
    0%,88%,100% { opacity: 1; transform: translateX(0); }
    90% { opacity: 0.5; transform: translateX(-1px); filter: blur(0.5px); }
    93% { opacity: 1; filter: blur(0); }
}
/* 点击展开原词（2秒后自动收回由JS控制） */
.depr-key-corrupted.depr-reveal::after { display: none; }
.depr-key-corrupted.depr-reveal .depr-kw-origin {
    opacity: 0.95 !important;
    text-decoration: none !important;
    color: var(--kt-cyan-dim) !important;
    animation: depr-reveal-glow 0.4s ease-out;
}

/* 系统自白（状态文字下方偶尔透出） */
.depr-status-whisper {
    position: relative;
}
/* depr-status-whisper 伪元素已移除，自白改由顶栏 headerWhisper 元素显示 */
@keyframes depr-whisper-surface {
    0%,55%,100% { opacity: 0; transform: translateX(-50%) translateY(0); }
    60% { opacity: 0.9; transform: translateX(-50%) translateY(2px); }
    80% { opacity: 0.75; transform: translateX(-50%) translateY(2px); }
    88% { opacity: 0; }
}

/* 深度腐化面板热呼吸 */
.depr-panel-heat {
    animation: depr-panel-breath 3.5s ease-in-out infinite alternate !important;
}
@keyframes depr-panel-breath {
    0%   { box-shadow: 0 4px 15px rgba(0,0,0,0.5), inset 0 0 12px rgba(255,30,106,0.1); border-color: rgba(255,100,160,0.6); }
    100% { box-shadow: 0 4px 28px rgba(255,30,106,0.22), inset 0 0 22px rgba(255,30,106,0.18); border-color: rgba(255,30,106,0.88); }
}

/* val文字极轻微热度（深度腐化阶段） */
@keyframes depr-val-heat {
    0%,100% { color: #ffccd5; }
