}

/* ========== 🚨 脱出模式·沉浸式警戒引擎 V2 深渊心跳版 ========== */
.escape-mode-active .kitten-bar-wrapper { transition: border-color 0.5s ease; border-color: rgba(255, 30, 106, 0.6); box-shadow: 0 4px 15px rgba(0,0,0,0.5), inset 0 0 10px rgba(255, 30, 106, 0.15); }
.escape-mode-active .bar-header { background: linear-gradient(90deg, rgba(30,0,10,0.7) 0%, rgba(10,0,0,0.85) 100%); border-bottom-color: rgba(255, 30, 106, 0.5) !important; }
.escape-tab-btn { background: linear-gradient(135deg, rgba(200,0,50,0.55) 0%, rgba(100,0,20,0.7) 100%) !important; border: 1px solid rgba(255, 30, 106, 0.9) !important; color: #ffb3c6 !important; box-shadow: 0 0 8px rgba(255, 30, 106, 0.5), inset 0 0 5px rgba(255,0,50,0.2) !important; animation: esc-tab-pulse 0.7s ease-in-out infinite alternate !important; font-family: monospace !important; letter-spacing: 1px !important; }
@keyframes esc-tab-pulse { 0% { box-shadow: 0 0 3px rgba(255, 30, 106, 0.25); opacity:0.9; } 100%{ box-shadow: 0 0 8px rgba(255, 30, 106, 0.45); opacity:1; } }
#tab-escape { position: relative; padding: 4px; overflow: hidden; }

/* 背景神经噪点干扰 */
.v2-scan-overlay { position: absolute; inset: 0; z-index: 0; pointer-events: none; background: repeating-linear-gradient( 0deg, transparent 0px, transparent 2px, rgba(255, 30, 106, 0.04) 2px, rgba(255, 30, 106, 0.04) 4px ); animation: v2-scan-drift 10s linear infinite; opacity: 0.8; border-radius: 8px;}
@keyframes v2-scan-drift { 100% { background-position: 0 200px; } }
.v2-content { position: relative; z-index: 10; display: flex; flex-direction: column; gap: 8px; }

/* 顶部横幅 */
.v2-alarm-banner { display: flex; align-items: center; justify-content: center; background: linear-gradient(90deg, rgba(255,30,106,0.15), rgba(0,0,0,0.6), rgba(255,30,106,0.15)); border-left: 3px solid var(--kt-alert); border-right: 3px solid var(--kt-alert); border-radius: 6px; padding: 6px 12px; box-shadow: inset 0 0 15px rgba(255,30,106,0.1); overflow: hidden; position: relative; animation: v2-banner-breathe 2s ease-in-out infinite alternate; }
.v2-alarm-banner::after { content: ''; position: absolute; top:0; left: -100%; width: 50%; height: 100%; background: linear-gradient(90deg, transparent, rgba(255,30,106,0.3), transparent); transform: skewX(-20deg); animation: v2-shimmer 3s infinite; }
@keyframes v2-banner-breathe { 100% { box-shadow: inset 0 0 25px rgba(255,30,106,0.25); border-color: #ff4d8c; } }
@keyframes v2-shimmer { 100% { left: 200%; } }
.v2-alarm-title { font-weight: 900; font-size: 0.8em; color: var(--kt-pink-dim); letter-spacing: 1.5px; text-shadow: 0 0 2px rgba(255,30,106,0.25); }
/* 雷达与距离卡片 (柔和动态紧凑版) */
.v2-radar-card {
    background: var(--esc-bg-grad, linear-gradient(135deg, rgba(15, 18, 30, 0.9), rgba(10, 10, 15, 0.95)));
    border: 1px solid var(--esc-border, rgba(255, 255, 255, 0.15));
    border-radius: 12px;
    padding: 8px 12px; /* 压榨留白 */
    display: flex; flex-direction: column; gap: 8px; /* 压榨留白 */
    box-shadow: 0 4px 15px var(--esc-shadow, rgba(0,0,0,0.5)), inset 0 0 15px var(--esc-glow, transparent);
    position: relative; overflow: hidden;
    transition: all 0.6s cubic-bezier(0.34, 1.56, 0.64, 1);
}
.v2-radar-card::before {
    content: ''; position: absolute; inset: 0;
    background: radial-gradient(ellipse at 100% 50%, var(--esc-bg-pulse, transparent), transparent 70%);
    pointer-events: none; transition: background 0.6s ease;
}
.v2-hunter-header { display: flex; justify-content: space-between; align-items: center; position: relative; z-index: 2; font-size: 0.7em; font-weight: 900; text-transform: uppercase; }
.zone-safe { color: #00f5ff; text-shadow: 0 0 3px rgba(0, 245, 255, 0.4); display: flex; align-items: center; gap: 4px; }
.zone-danger { color: #d1477a; display: flex; align-items: center; gap: 4px; }
.v2-pulse-red { width: 6px; height: 6px; border-radius: 50%; background: #d1477a; box-shadow: 0 0 5px #d1477a; animation: alert-blink-v2 0.8s infinite alternate; }
@keyframes alert-blink-v2 { 100% { opacity: 0.2; transform: scale(0.8); } }
/* 全息逃跑轨道 */
.v2-track-wrap { position: relative; height: 26px; display: flex; align-items: center; z-index: 2; }
.v2-track-line { width: 100%; height: 3px; background: linear-gradient(90deg, rgba(0,245,255,0.3) 0%, rgba(255,255,255,0.1) 40%, rgba(255,126,179,0.2) 80%, rgba(209,71,122,0.6) 100%); border-radius: 2px; position: relative; background-color: rgba(0,0,0,0.5); }
.v2-track-danger-fill { position: absolute; right: 0; top: -1px; bottom: -1px; background: var(--esc-fill-bg, rgba(0,245,255,0.1)); border-radius: 0 2px 2px 0; transition: width 0.3s ease-out, background 0.6s ease; }
.v2-target-icon { position: absolute; top: 50%; transform: translate(-50%, -50%); font-size: 18px; filter: drop-shadow(0 0 3px rgba(255,255,255,0.4)); z-index: 10; }
.v2-dist-val { text-align: center; font-family: monospace; font-size: 0.85em; color: var(--esc-text-color, #e8e8f2); font-weight: 900; letter-spacing: 1px; transition: color 0.5s, text-shadow 0.5s; position: relative; z-index: 2;}
/* 雷达动效与粒子 */
.danger-particle { position: absolute; width: 3px; height: 3px; border-radius: 50%; pointer-events: none; z-index: 5; animation: drift-left-v2 1.5s linear forwards; }
@keyframes drift-left-v2 { 0% { transform: translate(0, 0) scale(1.2); opacity: 0.6; } 100% { transform: translate(-30px, var(--ty)) scale(0); opacity: 0; } }
@keyframes cat-struggle { 0%, 100% { transform: translate(-50%, -50%) rotate(0deg); } 25% { transform: translate(-50%, -52%) rotate(-5deg); } 75% { transform: translate(-50%, -48%) rotate(5deg); } }
@keyframes cat-run { 0%, 100% { transform: translate(-50%, -50%) translateY(0); } 50% { transform: translate(-50%, -50%) translateY(-2px); } }
@keyframes cat-safe { 0%, 100% { transform: translate(-50%, -50%) scale(1); } 50% { transform: translate(-50%, -50%) scale(1.08); filter: drop-shadow(0 0 5px #00f5ff); } }
/* 双轨压力条 */
.v2-bars-grid { display: flex; flex-direction: column; gap: 8px; }
.v2-bar-item { background: rgba(0,0,0,0.3); border-radius: 8px; padding: 6px 10px; border: 1px solid rgba(255,255,255,0.05); }
.v2-bar-head { display: flex; justify-content: space-between; font-size: 0.7em; font-weight: 900; margin-bottom: 5px; color: var(--kt-cyan-dim); }
.v2-bar-num { font-family: monospace; color: #fff; }
.v2-progress-bg { width: 100%; height: 6px; background: rgba(0,0,0,0.6); border-radius: 10px; overflow: hidden; box-shadow: inset 0 1px 3px rgba(0,0,0,0.9); }
.v2-progress-fill { height: 100%; border-radius: 10px; position: relative; transition: width 0.5s; }
.fill-leak { background: linear-gradient(90deg, #b39ddb, #ff7eb3, #ff1e6a); }
.fill-expose { background: linear-gradient(90deg, #80deea, #ffe0ef, #ff1e6a); }
    .v2-progress-fill::after { content: ''; position: absolute; top: 0; bottom: 0; right: 0; width: 20px; background: linear-gradient(90deg, transparent, rgba(255,255,255,0.35)); filter: blur(2px); border-radius: 5px; }
/* 霜玻璃环境标签 */
.v2-chips-row { display: flex; flex-wrap: wrap; gap: 6px; }
.v2-chip { font-size: 0.65em; font-weight: 900; padding: 3px 8px; border-radius: 12px; background: rgba(255,255,255,0.05); backdrop-filter: blur(4px); -webkit-backdrop-filter: blur(4px); border: 1px solid rgba(255,255,255,0.1); display: flex; align-items: center; gap: 4px; color: #d1d5e5; text-shadow: 0 0 2px rgba(0,0,0,0.8); }
.chip-warn { border-color: rgba(255, 126, 179, 0.4); color: #ffccd5; background: rgba(255, 30, 106, 0.08); }
.chip-safe { border-color: rgba(162, 225, 219, 0.4); color: #d6f7ff; background: rgba(0, 245, 255, 0.05); }

/* 出路指引 */
.v2-route-wrap { display: flex; flex-direction: column; gap: 5px; }
.v2-route-title { font-size: 0.65em; font-weight: 900; color: #8c92a6; letter-spacing: 1px; }
.v2-route-item { display: flex; align-items: center; gap: 8px; background: linear-gradient(90deg, rgba(0,245,255,0.05), transparent); border-left: 2px solid var(--kt-cyan); border-radius: 4px; padding: 6px 10px; font-size: 0.75em; font-weight: 700; color: #e8e8f2; word-break: break-all;}
.v2-route-icon { font-size: 0.85em; opacity: 0.8; flex-shrink: 0;}

/* 底部状态机能网格 */
.v2-status-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; }
.v2-status-cell { background: rgba(0,0,0,0.4); border: 1px dashed rgba(255,255,255,0.1); border-radius: 6px; padding: 6px 8px; display: flex; flex-direction: column; gap: 2px; }
.v2-status-key { font-size: 0.6em; color: #8c92a6; font-weight: 900;}
.v2-status-val { font-size: 0.78em; font-weight: 900; color: #ffccd5; word-break: break-all;}
.v2-status-val.danger-text { color: #ff1e6a; text-shadow: 0 0 5px rgba(255,30,106,0.6); }

/* ========== 脱出模式样式结束 ========== */

/* ========== 🌏 世界观测室 GAZE_HUD 样式 新版 ========== */

:root {
    --gz-cyan: #00f5ff;
    --gz-cyan-dim: #a2e1db;
    --gz-pink: #ff7eb3;
    --gz-pink-dim: #ffb3c6;
    --gz-alert: #ff1e6a;
}

.gz-wrap {
    max-width: 420px; margin: 0 auto; padding: 8px;
    background: rgba(15,18,32,0.96);
    border-radius: 10px;
    border: 1px solid rgba(0,245,255,0.12);
    position: relative;
}

/* 网格干扰底纹 */
.gaze-v3-overlay {
    position: absolute; inset: 0; z-index: 0; pointer-events: none;
    background-image:
        linear-gradient(rgba(0,245,255,0.02) 1px, transparent 1px),
        linear-gradient(90deg, rgba(0,245,255,0.02) 1px, transparent 1px);
    background-size: 8px 8px; opacity: 0.6;
    border-radius: inherit;
}

.v3-content { position: relative; z-index: 10; display: flex; flex-direction: column; gap: 6px; padding: 2px 4px; }

/* 顶部横幅 */
.gaze-banner {
    display: flex; align-items: center; justify-content: center;
    border-bottom: 1px dashed rgba(0,245,255,0.35);
    padding-bottom: 6px; margin-bottom: 4px; margin-top: 2px;
}
.gaze-title {
    font-size: 0.85em; font-weight: 900; color: var(--gz-cyan);
    letter-spacing: 2px; text-shadow: 0 0 4px rgba(0,245,255,0.4);
    display: flex; align-items: center; gap: 6px;
}
.gaze-title::before { content: '👁️'; filter: hue-rotate(180deg); animation: blinkEye 3.5s infinite; font-size: 1.1em; }
@keyframes blinkEye { 0%,96%,100%{opacity:1;transform:scaleY(1);} 98%{opacity:0;transform:scaleY(0.1);} }

/* 分区标题 */
.gz-sec {
    display: flex; align-items: center; gap: 5px;
    font-size: 0.65em; font-weight: 900; color: var(--text-sub);
    letter-spacing: 0.8px; margin: 8px 0 5px;
    text-transform: uppercase;
}
.gz-sec span { opacity: 0.75; font-size: 1.15em; }
.gz-sec::after {
    content: ''; flex: 1; height: 1px;
    background: linear-gradient(90deg, rgba(162,225,219,0.2), transparent);
}

/* 大组折叠标题 */
.gz-group-title {
    display: flex; align-items: center; gap: 6px;
    font-size: 0.7em; font-weight: 900; color: var(--gz-cyan-dim);
    letter-spacing: 1px; margin: 10px 0 6px;
    padding: 5px 8px;
    background: rgba(0,245,255,0.04);
    border-left: 2px solid rgba(0,245,255,0.35);
    border-radius: 0 5px 5px 0;
    text-shadow: 0 0 4px rgba(0,245,255,0.3);
}
.gz-group-title::after {
    content: ''; flex: 1; height: 1px;
    background: linear-gradient(90deg, rgba(0,245,255,0.2), transparent);
}

/* 胶囊印戳行 */
.gz-stamp-row { display: flex; flex-wrap: wrap; gap: 5px; margin-bottom: 4px; }
.gz-pill {
    display: inline-flex; align-items: baseline; gap: 3px;
    background: rgba(0,0,0,0.38);
    border: 1px solid rgba(162,225,219,0.14);
    border-radius: 6px; padding: 4px 8px;
    font-family: monospace;
}
.gz-pill.warn  { border-color: rgba(255,126,179,0.32); background: rgba(255,30,106,0.06); }
.gz-pill.danger{ border-color: rgba(255,30,106,0.52); background: rgba(255,30,106,0.1); }
.gz-pill.safe  { border-color: rgba(0,245,255,0.22); background: rgba(0,245,255,0.04); }

.gz-pill-icon { font-size: 0.75em; line-height: 1; }
.gz-pill-key  { font-size: 0.68em; font-weight: 900; color: var(--text-sub); font-family: monospace; flex-shrink: 0; }
.gz-pill-val  { font-size: 0.78em; font-weight: 900; color: var(--text-main); }
.gz-pill-val.c-cyan  { color: var(--gz-cyan);    text-shadow: 0 0 4px rgba(0,245,255,0.5); }
.gz-pill-val.c-pink  { color: var(--gz-pink);    text-shadow: 0 0 4px rgba(255,126,179,0.5); }
.gz-pill-val.c-alert { color: var(--gz-alert);   text-shadow: 0 0 4px rgba(255,30,106,0.6); }
