/* 数据行：单行键值（长文本） */
.gz-row {
    display: flex; align-items: flex-start; gap: 6px;
    padding: 5px 8px;
    background: rgba(0,0,0,0.25);
    border-left: 2px solid rgba(162,225,219,0.28);
    border-radius: 3px; margin-bottom: 4px;
}
.gz-row.warn   { border-left-color: rgba(255,126,179,0.48); background: rgba(255,30,106,0.05); }
.gz-row.danger { border-left-color: rgba(255,30,106,0.62); background: rgba(255,30,106,0.08); }
.gz-row-key {
    font-size: 0.64em; font-weight: 900; color: var(--text-sub);
    font-family: monospace; white-space: nowrap; flex-shrink: 0; padding-top: 1px;
}
.gz-row-val {
    font-size: 0.76em; font-weight: 700; color: var(--text-main); line-height: 1.45;
}
.gz-row.danger .gz-row-val { color: #ffccd5; }
.gz-row.warn   .gz-row-val { color: var(--gz-pink-dim); }

/* 自我凝视：媒介+烈度同行胶囊 */
.gz-gaze-meta { display: flex; gap: 5px; flex-wrap: wrap; margin-bottom: 4px; }

/* 信息素感知条 */
.gz-pheromone {
    display: flex; align-items: center; gap: 7px;
    padding: 5px 8px; background: rgba(0,0,0,0.28);
    border-radius: 5px; margin-bottom: 4px;
}
.gz-ph-icon  { font-size: 0.8em; flex-shrink: 0; }
