.gz-ph-track { flex: 1; height: 4px; background: rgba(255,255,255,0.07); border-radius: 99px; overflow: hidden; }
.gz-ph-fill  {
    height: 100%; border-radius: 99px;
    background: linear-gradient(90deg, #18e0d4 0%, #a8ffee 30%, #ff7eb3 75%, #ff1e6a 100%);
    transition: width 0.8s;
}
.gz-ph-val { font-size: 0.68em; font-weight: 900; color: var(--gz-pink-dim); flex-shrink: 0; font-family: monospace; white-space: nowrap; }

/* 曝光进度条 */
.gz-expose { margin: 4px 0 6px; }
.gz-expose-head {
    display: flex; justify-content: space-between; align-items: center;
    font-size: 0.64em; font-family: monospace; font-weight: 900;
    color: rgba(200,200,200,0.65); margin-bottom: 4px;
}
.gz-expose-num { color: var(--gz-pink-dim); }
.gz-expose-bg {
    width: 100%; height: 5px; background: rgba(255,255,255,0.06);
    border-radius: 99px; overflow: hidden; box-shadow: inset 0 1px 2px rgba(0,0,0,0.8);
}
.gz-expose-fill {
    height: 100%; border-radius: 99px;
    background: linear-gradient(90deg, #18e0d4 0%, #a8ffee 30%, #ff7eb3 75%, #ff1e6a 100%);
    box-shadow: inset 0 1px 2px rgba(255,255,255,0.3); transition: width 0.6s;
}
.gz-expose-fill.is-high { animation: gz-expose-flash 0.6s ease-in-out infinite alternate; }
@keyframes gz-expose-flash { 100% { box-shadow: 0 0 8px rgba(255,30,106,0.7); filter: brightness(1.3); } }

/* 听觉泄漏标签 */
.gz-audio-tag {
    display: inline-flex; align-items: center; gap: 3px;
    background: rgba(255,126,179,0.1); border: 1px solid rgba(255,126,179,0.38);
    border-radius: 5px; padding: 3px 7px;
