}
@keyframes audio-blink { 100% { border-color: rgba(255,126,179,0.75); box-shadow: 0 0 5px rgba(255,126,179,0.3); } }

/* NPC视角气泡 */
.gz-npc-block { background: rgba(0,0,0,0.2); border-radius: 6px; padding: 5px 7px; margin-bottom: 4px; display: flex; flex-direction: column; gap: 4px; }
.gz-npc-item  { display: flex; gap: 5px; align-items: flex-start; }
.gz-npc-role  {
