}
.gz-card-name { font-size: 0.8em; font-weight: 900; color: #e9d5ff; flex: 1; }
.gz-card-badge {
    font-size: 0.6em; font-weight: 900; padding: 2px 6px; border-radius: 5px;
    font-family: monospace; flex-shrink: 0;
}
.badge-curious { color: var(--gz-cyan-dim); border: 1px solid rgba(162,225,219,0.42); background: rgba(162,225,219,0.06); }
.badge-stalk   { color: var(--gz-pink);     border: 1px solid rgba(255,126,179,0.52); background: rgba(255,30,106,0.08); }
