}
.gz-card-val { font-size: 0.76em; font-weight: 700; color: var(--text-main); line-height: 1.4; }
.gz-card-val.c-pink  { color: var(--gz-pink-dim); }
.gz-card-val.c-alert { color: #ffccd5; }

