}
.gz-countdown-fill.urgent { animation: countdown-flare 0.5s ease-in-out infinite alternate; }
@keyframes countdown-flare { 100% { box-shadow: 0 0 6px rgba(255,30,106,0.8); filter: brightness(1.4); } }
.gz-countdown-val { font-size: 0.66em; font-weight: 900; color: var(--gz-pink-dim); flex-shrink: 0; font-family: monospace; white-space: nowrap; }
