/* 终极压力池 */
.v3-doom-card {
    display: flex; align-items: center; gap: 10px;
    background: rgba(25,5,10,0.85); border: 1px solid rgba(255,30,106,0.4);
    border-radius: 8px; padding: 10px; margin-top: 2px;
    animation: doom-breath 2.5s ease-in-out infinite alternate;
