    /* 控制台底层防卡滑动与护眼重构 */
    .admin-console-wrapper {
        position: absolute; top: 10px; left: -95vw;
        width: 90vw; max-width: 600px;
        max-height: 85vh; padding: 12px 10px;
        background: rgba(8, 9, 13, 0.98); /* 夜间深色降亮底色 */
        border: 1px solid rgba(255,126,179,0.3); /* 降低外边框攻击性 */
        border-radius: 12px;
        box-shadow: 5px 10px 30px rgba(0,0,0,0.9), inset 0 0 20px rgba(255,126,179,0.1);
        z-index: 1000; transition: left 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
        backdrop-filter: blur(15px); -webkit-backdrop-filter: blur(15px);
        display: flex; flex-direction: column; gap: 12px;
        transform: translateZ(0);
        /* 核心修复：顺滑滚动，防止被上层锁死 */
        overflow-y: auto; overflow-x: hidden;
        overscroll-behavior: contain;
        -webkit-overflow-scrolling: touch;
        touch-action: pan-y;
    }
    .admin-console-wrapper.show { left: 5px; }
    .admin-console-wrapper::-webkit-scrollbar { width: 4px; }
    .admin-console-wrapper::-webkit-scrollbar-thumb { background: rgba(255,126,179,0.5); border-radius: 4px; }

    .admin-title {
        font-size: 1.05em; font-weight: 900; color: rgba(255,255,255,0.85);
        text-shadow: 0 0 6px rgba(255,126,179,0.4); text-align: center;
        border-bottom: 1px dashed rgba(255,126,179,0.3);
        padding-bottom: 8px; margin-bottom: 4px; letter-spacing: 1px;
    }

    /* 指令按钮柔和重构 */
    .cmd-btn {
        background: rgba(255,255,255,0.03); /* 取消辣眼睛的红橙色底，改用透明灰 */
        border: 1px solid rgba(255,255,255,0.08); /* 极弱边框 */
        border-radius: 8px; padding: 8px 6px;
        cursor: pointer; display: flex; flex-direction: column;
        justify-content: flex-start; align-items: flex-start;
        transition: transform 0.2s, background 0.2s, border-color 0.2s, box-shadow 0.2s;
        text-align: left; position: relative; min-height: 55px;
    }
    .cmd-btn:hover { background: rgba(255,255,255,0.07); border-color: rgba(255,255,255,0.15); transform: translateY(-1px); box-shadow: 0 2px 6px rgba(0,0,0,0.5); }
    .cmd-btn:active { transform: scale(0.97); }
    .cmd-btn-header { display: flex; justify-content: space-between; width: 100%; align-items: flex-start; margin-bottom: 4px; }
    .cmd-btn-title { font-size: 0.72em; font-weight: 900; color: #d1d5e5; line-height: 1.2; word-break: break-all; }
    .cmd-icon { font-size: 0.8em; opacity: 0.5; flex-shrink: 0; margin-left: 4px; }
    .cmd-desc { font-size: 0.65em; color: rgba(255,255,255,0.45); font-weight: normal; line-height: 1.35; }

    /* 控制台专属折叠样式 */
    details.admin-fold {
        background: rgba(0,0,0,0.3); border-radius: 8px;
        border-left: 3px solid var(--fold-color, #666);
        margin-bottom: 6px; transition: all 0.3s;
        box-shadow: inset 0 0 5px rgba(0,0,0,0.5);
        overflow: clip; /* overflow:hidden 会在动画帧截断summary文字，clip更安全 */
}
    details.admin-fold[open] {
        background: rgba(20,20,30,0.4);
        box-shadow: inset 0 0 10px rgba(0,0,0,0.8), 0 2px 5px rgba(0,0,0,0.3);
        border-bottom: 1px solid rgba(255,255,255,0.03);
    }
    summary.admin-fold-title {
        padding: 8px 10px; cursor: pointer; display: flex; justify-content: space-between; align-items: center;
        user-select: none; position: relative; gap: 8px; /* 加入 gap 防止文字贴贴 */
    }
    summary.admin-fold-title::-webkit-details-marker { display: none; }

    /* 核心修复：防止标签折叠错位 */
    summary.admin-fold-title span:first-child {
        font-size: 0.85em; font-weight: 900; color: var(--fold-color, #ccc);
        flex-shrink: 0;
        white-space: nowrap;       /* 核心修复：强制不折行 */
        overflow: visible;         /* 确保不被裁剪 */
        text-shadow: 0 0 4px rgba(255,255,255,0.1);
}
    summary.admin-fold-title .fold-desc {
        font-size: 0.65em; color: rgba(255,255,255,0.4); font-weight: normal;
        flex: 1; text-align: right; /* 副标题靠右 */
        white-space: nowrap; overflow: hidden; text-overflow: ellipsis; /* 长了就变成省略号 */
    }
    summary.admin-fold-title::after {
        content: '▼'; font-size: 0.7em; opacity: 0.5; transition: transform 0.3s;
        font-family: monospace; flex-shrink: 0; color: var(--fold-color); margin-left: 2px;
    }
    details.admin-fold[open] summary.admin-fold-title::after { transform: rotate(180deg); opacity: 0.8;}

    .admin-fold-content {
        display: grid; grid-template-columns: repeat(2, 1fr); gap: 6px;
        padding: 6px 8px 10px 8px; border-top: 1px dashed rgba(255,255,255,0.03);
    }

    #copyToast { position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%) scale(0.8); background: rgba(0, 0, 0, 0.9); border: 2px solid #00f5ff; color: #fff; padding: 15px 30px; border-radius: 12px; font-weight: 900; box-shadow: 0 10px 30px rgba(0,245,255,0.5); opacity: 0; pointer-events: none; transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1); z-index: 9999; font-size: 1.1em; text-align: center; max-width: 80vw; white-space: normal; word-break: break-all; backdrop-filter: blur(5px);}
    #copyToast.show { transform: translate(-50%, -50%) scale(1); opacity: 1; }
/* ════ 关系Tab & 背德Tab 极致精简版 ════ */
/* 1. 全局与标题 */
.rc-title { display: flex; align-items: center; gap: 6px; font-size: 0.82em; font-weight: 900; color: #e1bee7; letter-spacing: 0.8px; margin: 10px 0 6px; text-transform: uppercase; }
.rc-title::after { content: ''; flex: 1; height: 1px; background: linear-gradient(90deg, rgba(206,147,216,0.3), transparent); }
.rc-title:first-child { margin-top: 4px; }
.rc-div { height: 1px; background: linear-gradient(90deg, transparent, rgba(206,147,216,0.14), transparent); margin: 6px 0; }

/* 2. 通用卡片容器 (Box) 与 网格 (Grid) */
/* 🌟核心修复：增加 color: #e8e0f0; 甚至用 !important 强制继承，护死所有内部文本 */
.rc-box {
    border-radius: 12px; padding: 10px 12px; margin-bottom: 6px; position: relative; overflow: hidden;
    border: 1px solid var(--bx-bd, rgba(255,255,255,0.1));
    background: var(--bx-bg, rgba(0,0,0,0.3));
    color: #e8e0f0 !important;
}
.rc-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 4px; }
.rc-gi { background: rgba(0,0,0,0.22); border-radius: 8px; padding: 5px 8px; display: flex; flex-direction: column; gap: 2px; }

/* 3. 通用数据行 (Row) 与 键值 (Key/Val) */
.rc-row { display: flex; align-items: flex-start; gap: 8px; padding: 2px 0; border-bottom: 1px solid rgba(255,255,255,0.03); }
.rc-row:last-child { border-bottom: none; }
.rc-k { font-size: 0.7em; font-weight: 900; color: rgba(220,200,240,0.5); font-family: monospace; flex-shrink: 0; min-width: 54px; padding-top: 1px; }
.rc-v { font-size: 0.84em; font-weight: 700; color: #e8e0f0 !important; line-height: 1.45; flex: 1; }

/* 4. 辅助高亮文本与标签 (Badge/Text) */
.txt-red { color: #f48fb1 !important; text-shadow: 0 0 5px rgba(244,143,177,0.35); }
.txt-gold { color: #fde68a !important; }
.txt-cyan { color: #a2e1db !important; }
.txt-dim { color: rgba(255,180,200,0.7) !important; font-style: italic; }
.txt-white { color: #ffffff !important; }
.rc-badge { font-size: 0.65em; font-weight: 900; padding: 2px 8px; border-radius: 8px; border: 1px solid; background: rgba(0,0,0,0.2); }
.bg-red { background: rgba(244,143,177,0.14); color: #f48fb1; border-color: rgba(244,143,177,0.38); }
.bg-gold { background: rgba(253,230,138,0.1); color: #fde68a; border-color: rgba(253,230,138,0.28); }
.bg-cyan { background: rgba(128,222,234,0.1); color: #a2e1db; border-color: rgba(128,222,234,0.22); }
