.ani-pulse { animation: rc-pulse 1.5s ease-in-out infinite alternate; }
@keyframes rc-pulse { 0%{opacity:0.75;} 100%{opacity:1; filter:drop-shadow(0 0 4px currentColor);} }

/* 5. 进度条/双轨比例条 (Bar) */
.rc-bar-wrap { padding: 6px 0; margin-bottom: 2px; }
.rc-bar-hd { display: flex; justify-content: space-between; font-size: 0.65em; font-weight: 900; color: rgba(220,200,240,0.5); font-family: monospace; margin-bottom: 4px; }
.rc-track { height: 4px; border-radius: 99px; background: rgba(255,255,255,0.06); overflow: hidden; display: flex; }
