/* 6. 特异性组件衍生设定 (极简覆写) */
.shura-box::before, .dep-box::before { content: ''; position: absolute; top:0; left:0; right:0; height:2px; background: linear-gradient(90deg, #f48fb1, #ce93d8, #f48fb1); background-size: 200% 100%; animation: rc-sweep 3s linear infinite; }
@keyframes rc-sweep { 100%{background-position: -200% 0;} }
