    pointer-events: none;
}

/* ── 卡片顶栏 ── */
.st-head {
    display: flex; align-items: center; justify-content: space-between;
    padding: 9px 12px 8px;
    border-bottom: 1px solid rgba(255,179,198,0.1);
    background: linear-gradient(90deg, rgba(255,179,198,0.07), rgba(129,212,250,0.04), transparent);
