    box-shadow: 0 0 6px rgba(255,179,198,0.8), 0 0 12px rgba(129,212,250,0.4);
    animation: st-dot 2s ease-in-out infinite alternate;
}
@keyframes st-dot {
    0% { transform: scale(0.82); opacity: 0.65; box-shadow: 0 0 3px rgba(255,179,198,0.5); }
    100% { transform: scale(1.18); opacity: 1; box-shadow: 0 0 9px rgba(255,179,198,0.9), 0 0 16px rgba(129,212,250,0.5); }
}
.st-head-title {
    font-size: 0.72em; font-weight: 900; letter-spacing: 0.8px;
    background: linear-gradient(90deg, #ffb3c6, #c5a3ff 45%, #81d4fa);
    -webkit-background-clip: text; -webkit-text-fill-color: transparent;
}
.st-badge {
    font-size: 0.58em; font-weight: 900; padding: 2px 7px; border-radius: 8px;
    font-family: monospace; letter-spacing: 0.4px;
    background: linear-gradient(90deg, rgba(255,179,198,0.1), rgba(129,212,250,0.08));
