@keyframes st-badge-breathe { 0%{opacity:0.65} 100%{opacity:1;filter:drop-shadow(0 0 3px rgba(255,179,198,0.4));} }
@keyframes st-danger-blink { 0%,100%{opacity:1} 50%{opacity:0.3} }

