/* ── 弹幕点赞动效 ── */
@keyframes danmaku-like-rise {
    0%   { opacity:0.9; transform:translateY(-50%) scale(0.8); }
    45%  { opacity:1;   transform:translateY(calc(-50% - 9px)) scale(1.18); }
    100% { opacity:0;   transform:translateY(calc(-50% - 24px)) scale(0.9); }
}
@keyframes danmaku-resonate {
    0%,100% { transform:translateX(0) scaleY(1); }
    20%     { transform:translateX(-2px) scaleY(0.97); }
    45%     { transform:translateX(3px) scaleY(1.02); }
    70%     { transform:translateX(-1.5px); }
    88%     { transform:translateX(1px); }
}
/* ── 灵魂气泡被戳动效 ── */
@keyframes soul-poke-shy {
    0%,100% { transform:translate(0,0) rotate(0deg); }
    15%     { transform:translate(-2px,-1px) rotate(-0.5deg); }
    30%     { transform:translate(3px,1px) rotate(0.4deg); }
    48%     { transform:translate(-2px,0) rotate(-0.3deg); }
    65%     { transform:translate(1px,-0.5px); }
    80%     { transform:translate(-0.5px,0.5px); }
}
@keyframes soul-overwhelm {
    0%,100% { transform:translate(0,0) scale(1); filter:blur(0); }
    18%     { transform:translate(-3px,1px) scale(0.99); filter:blur(0.4px); }
    36%     { transform:translate(4px,-1px) scale(1.01); filter:blur(0.6px); }
    54%     { transform:translate(-2px,0) scale(0.995); filter:blur(0.3px); }
    72%     { transform:translate(1.5px,0.5px); filter:blur(0.15px); }
    88%     { transform:translate(-0.5px,0); }
}
@keyframes soul-emoji-pop {
    0%   { transform:translate(-50%,-50%) scale(0.4) rotate(0deg); opacity:1; }
    55%  { transform:translate(calc(-50% + var(--tx)/2), calc(-50% + var(--ty)/2)) scale(1.3) rotate(var(--rot)); opacity:1; }
    100% { transform:translate(calc(-50% + var(--tx)), calc(-50% + var(--ty))) scale(0.9) rotate(calc(var(--rot)*1.5)); opacity:0; }
}
/* ══════*/
/* 🧠 局部神经末梢反馈测试 (Neuro-Reflex)         */
/* ═════*/
.is-sensitive-node {
    cursor: pointer;
    position: relative;
}
/* ⚡ 轻度戳弄痉挛 (单次点击) */
.reflex-twitch {
    animation: spasm-twitch 0.4s cubic-bezier(0.36, 0.07, 0.19, 0.97) forwards !important;
    background: rgba(255, 30, 106, 0.15) !important;
}
/* 🔥 强烈受激退缩 (连续点击/长按) */
.reflex-overload {
    animation: spasm-cringe 0.6s cubic-bezier(0.36, 0.07, 0.19, 0.97) forwards !important;
    background: rgba(255, 30, 106, 0.3) !important;
    border-color: #ff1e6a !important;
    color: #ffb3c6;
}
@keyframes spasm-twitch {
    0%   { transform: scale(1) translateX(0); filter: blur(0); }
