    /* 底部幽蓝海潮光晕 */
    .siren-tide-bg {
        position: absolute; bottom: 0; left: 0; width: 100%; height: 60%;
        background: linear-gradient(180deg, transparent 0%, rgba(0, 150, 255, 0.12) 40%, rgba(0, 90, 180, 0.35) 100%);
        animation: siren-tide-flow 4s ease-in-out infinite alternate;
        pointer-events: none;
    }
