        100% { opacity: 1; transform: translateY(0px); filter: hue-rotate(15deg); }
    }
    /* 满屏水波折射纹理 */
    .siren-caustics {
        position: absolute; inset: 0; opacity: 0.15; mix-blend-mode: screen; pointer-events: none;
        background-image: radial-gradient(circle at 50% 50%, rgba(0,255,255,0.8) 1px, transparent 1px), radial-gradient(circle at 20% 80%, rgba(0,200,255,0.6) 2px, transparent 2px);
        background-size: 40px 40px;
