    }
    @keyframes siren-caustics-drift {
        0% { background-position: 0 0, 0 0; }
        100% { background-position: 40px -40px, -20px -50px; }
    }
    /* 荧光气泡 */
    .siren-bubble {
        position: absolute; bottom: -10px; border-radius: 50%; pointer-events: none;
        box-shadow: inset 0 0 6px rgba(0, 255, 255, 0.8), 0 0 4px rgba(0, 200, 255, 0.5);
        border: 1px solid rgba(180, 255, 255, 0.4); opacity: 0;
        animation: siren-bubble-rise var(--sb-dur, 4s) ease-in var(--sb-del, 0s) infinite;
    }
    @keyframes siren-bubble-rise {
        0% { opacity: 0; transform: translate(0, 0) scale(0.5); }
        15% { opacity: var(--sb-op, 0.7); }
        85% { opacity: 0.4; }
        100% { opacity: 0; transform: translate(var(--sb-x, 20px), -200px) scale(1.2); }
