        fill: url(#siren-fin-grad); opacity: 0;
        transform-origin: bottom right;
        animation: siren-fin-sway 5s ease-in-out forwards, siren-fin-breathe 4s ease-in-out 5s infinite alternate;
    }
    .siren-fin-left { transform-origin: bottom left; }
    @keyframes siren-fin-sway {
        0% { opacity: 0; transform: scaleY(0) skewX(20deg); }
        100% { opacity: var(--fin-op, 0.6); transform: scaleY(1) skewX(0deg); }
    }
    @keyframes siren-fin-breathe {
        0% { transform: rotate(0deg) scale(1); filter: drop-shadow(0 0 5px rgba(0,255,255,0.3)); opacity: var(--fin-op, 0.6); }
        100% { transform: rotate(3deg) scale(1.02); filter: drop-shadow(0 0 12px rgba(0,200,255,0.6)); opacity: calc(var(--fin-op, 0.6) * 1.2); }
    }
    /* 鳞片亮片闪烁 */
    .siren-scale-spark {
