        };
        const checkSlimeLens = (text) => { if(!text) return false; return /(满溢|喷射|白浊|内射|灌满|黏腻|糊成一片|大量|泡沫)/.test(text); };

        // 📡 腔道接入雷达 - 动态速率解析扩容版
const thrustTargetKeys = ['小逼异物', '后庭异物', '子宫异物', '口部异物', '镜头焦点', '阴茎', '龟头'];
