        const tubeKeys = ['今日精液摄入量', '今日射入摄取', '体内残留精液_口部', '体内残留精液_女穴', '体内残留精液_后庭', '今日被迫产奶量'];

        // 🔆 理智光谱剥落引擎 (五阶段变色)
