/* 🧠 神经反射交互触控引擎 (动态附着版-无震动)      */
/* ══════*/
(function initNeuroReflex() {
    const inherentSensors = ['阴蒂', '小逼', '子宫', '奶子', '后庭', '宫颈', '结肠'];
    const sensitiveKeywords = /(敏感|发软|颤|痉挛|痛|肿|酸|湿|水|潮|发热|酥麻|红|媚肉|爽|娇|烫)/;

    // 监听DOM变动，给动态生成的部位打上敏感标签
    const observer = new MutationObserver((mutations) => {
        const bodyTab = document.getElementById('tab-body');
        if (!bodyTab) return;
        const items = bodyTab.querySelectorAll('.body-grid-item, .data-row:not(.horizontal)');
        items.forEach(el => {
            if(el.dataset.neuroBound) return; // 已经处理过则跳过

            const keyEl = el.querySelector('.bgi-key, .data-key');
            const valEl = el.querySelector('.bgi-val, .data-val');
            if(!keyEl || !valEl) return;

            const keyText = keyEl.textContent;
            const valText = valEl.textContent;

            // AI语义识别：是不是敏感部位？
            let isNerveActive = false;
            if (inherentSensors.some(sk => keyText.includes(sk))) {
                isNerveActive = true;
            } else if (sensitiveKeywords.test(valText)) {
                isNerveActive = true;
            }

            if(isNerveActive) {
                el.classList.add('is-sensitive-node');
                bindNerveEvents(el);
            }
            el.dataset.neuroBound = "1";
        });
    });

    const swipeContainer = document.getElementById('swipeContainer');
    if (swipeContainer) {
        observer.observe(swipeContainer, { childList: true, subtree: true });
    }

    // 核心事件绑定大包
    function bindNerveEvents(el) {
        let touchTimer = null;
        let clickCount = 0;
        let resetCountTimer = null;

        function squirt(e, el) {
            const rect = el.getBoundingClientRect();
            // 防止 e.clientX 缺失时的兼容容错
            const cx = ((e.touches ? e.touches[0].clientX : e.clientX) || rect.left + rect.width/2) - rect.left;
            const cy = ((e.touches ? e.touches[0].clientY : e.clientY) || rect.top + rect.height/2) - rect.top;

            for(let i=0; i<3; i++) {
                let drop = document.createElement('div');
                drop.className = 'squirt-drop';
                drop.style.left = cx + 'px';
                drop.style.top = cy + 'px';

                let angle = Math.random() * Math.PI * 2;
                let force = 20 + Math.random() * 30;
                drop.style.setProperty('--dx', (Math.cos(angle) * force) + 'px');
                drop.style.setProperty('--dy', (Math.sin(angle) * force - 10) + 'px');

                el.appendChild(drop);
                setTimeout(() => drop.remove(), 600);
            }
        }

        function triggerTwitch() {
            el.classList.remove('reflex-twitch', 'reflex-overload');
            void el.offsetWidth;
            el.classList.add('reflex-twitch');
        }

        function triggerOverload(e) {
            el.classList.remove('reflex-twitch', 'reflex-overload');
            void el.offsetWidth;
            el.classList.add('reflex-overload');
            squirt(e, el);
            // （震动音效已安全摘除）
        }

        const handleStart = (e) => {
            // 🛡️ 核心护盾：防止点到数值复写框，以及处于【腐化状态的标题词】时误触发痉挛
            if(e.target.closest('.editable-val') || e.target.closest('.depr-key-corrupted')) return;

            touchTimer = setTimeout(() => {
                triggerOverload(e);
            }, 450); // 按住 0.45秒 触发高潮过载
        };

        const handleEnd = (e) => {
            // 🛡️ 同样拦截：点在这些功能性文字上时，直接放行原本的点击事件
            if(e.target.closest('.editable-val') || e.target.closest('.depr-key-corrupted')) return;
            clearTimeout(touchTimer);

            clickCount++;
            clearTimeout(resetCountTimer);

            if (clickCount >= 3) { // 快点3次直接喷水
                triggerOverload(e);
                clickCount = 0;
            } else {
                triggerTwitch();
            }

            resetCountTimer = setTimeout(() => {
                clickCount = 0;
            }, 400);
        };

        el.addEventListener('mousedown', handleStart);
        el.addEventListener('touchstart', handleStart, {passive: true});

        el.addEventListener('mouseup', handleEnd);
        el.addEventListener('touchend', handleEnd);

        el.addEventListener('mouseleave', () => clearTimeout(touchTimer));
        el.addEventListener('touchcancel', () => clearTimeout(touchTimer));
    }
})();

/* ══════
   🩸 生理期Tab · 双阶段自动渲染引擎
   数据来源：rawData 中 [生理周期] / [经期生理症状] / [经期卫生状态]
   触发条件：存在 [生理周期] 字段时显示Tab，否则整块隐藏
   自动切换：下腹痉挛="阵发绞痛/无法直立" 或 卫生用品吸收="已满/快满" → cycle-alert
              其余情况 → cycle-normal
═══ */
(function renderCycleTab(rawText) {

    const cycleBtn = document.getElementById('tabIconCycle');
    const cycleTabEl = document.getElementById('tab-cycle');
    if (!cycleBtn || !cycleTabEl) return;

    // ── 解析 [生理周期] 字段 ──
    const lines = rawText.split('\n');
    const cycleData = {};
    const symptomData = {};
    const hygieneData = {};

    let inCycle = false, inSymptom = false, inHygiene = false;
    let hadSymptomBlock = false; // 新增：记录是否真的出现过 [经期生理症状] 标题
    lines.forEach(l => {
        const t = l.trim();
        if (t.includes('生理周期')) { inCycle = true; inSymptom = false; inHygiene = false; return; }
        if (t.includes('经期生理症状') && t.startsWith('[')) { inSymptom = true; inCycle = false; inHygiene = false; hadSymptomBlock = true; return; }
        if (t.includes('排卵期特殊症状') && t.startsWith('[')) { inSymptom = true; inCycle = false; inHygiene = false; return; }
        if (t.includes('经期卫生状态') && t.startsWith('[')) { inHygiene = true; inCycle = false; inSymptom = false; return; }
        if (t.startsWith('[') && (t.endsWith(']') || t.endsWith('——')) && !t.includes('生理周期') && !t.includes('经期')) {
            inCycle = false; inSymptom = false; inHygiene = false; return;
        }
        const sep = t.indexOf(':'); if (sep === -1) return;
        const k = t.slice(0, sep).trim();
        const v = t.slice(sep + 1).trim();
        if (!v) return;
        if (inCycle) cycleData[k] = v;
        else if (inSymptom) symptomData[k] = v;
        else if (inHygiene) hygieneData[k] = v;
    });

    // ── 未触发：隐藏Tab整块 ──
    const hasCycleData = Object.keys(cycleData).length > 0;
    if (!hasCycleData) {
        cycleBtn.style.display = 'none';
        cycleTabEl.innerHTML = '';
        return;
    }
    cycleBtn.style.display = '';

    // ── 自动切换阶段判断 ──
    const crampVal   = (symptomData['下腹痉挛'] || '').toLowerCase();
    const hygAbsorb  = (hygieneData['吸收状态'] || '').toLowerCase();
    const isAlertMode =
        /阵发绞痛|无法直立/.test(crampVal) ||
        /已满|快满/.test(hygAbsorb);

    const phaseClass = isAlertMode ? 'cycle-alert' : 'cycle-normal';

    // ── 环形进度计算 ──
    const curDayRaw = cycleData['当前周期第'] || '';
    const curDay = parseInt(curDayRaw.match(/\d+/) ? curDayRaw.match(/\d+/)[0] : 1);
    const totalDay = 28;
    const circumference = 194.8;
    const offset = (circumference * (1 - curDay / totalDay)).toFixed(1);

    // ── 进度条位置计算 ──
    const phaseStr = cycleData['当前阶段'] || '';
    let psFillPct = 5;
    let psLeftLabel = '行经期', psCenterLabel = '', psRightLabel = '排卵期';
    if (/行经期/.test(phaseStr)) { psFillPct = Math.min(curDay / 5 * 100 * 0.15, 14); psLeftLabel = '行经期 ▲'; psCenterLabel = '行经第' + curDay + '天'; }
    else if (/卵泡期/.test(phaseStr)) { psFillPct = 15 + (curDay - 5) / 9 * 35; psCenterLabel = '卵泡期 ▲ 第' + curDay + '天'; }
    else if (/排卵期/.test(phaseStr)) { psFillPct = 52; psCenterLabel = '排卵期 ▲'; }
